'use strict';
const $ = s => document.querySelector(s);
const $$ = s => Array.from(document.querySelectorAll(s));
let MANIFEST=null, META=[], BY_ID=new Map(), BUCKET=new Map(), DATA_CACHE=new Map();
const MEMO={latticePoints:new Map(),stats:new Map(),automorphisms:new Map()};
let renderStop=false, currentOpen=null, selectedOrigin=null, viewState={rot:0,fx:false,fy:false};
let DRAW_SELECTED=new Set(), DRAW_GRID_N=13, DRAW_AUTO_ORIGIN=null, NEIGHBOR_TASKS=[], EDGE_DICT=[], MULT_DICT=[];
let BLOWUP_LAST=null, PF_CANCEL=null;
const RECORD_CARD_OPEN_STATE=new Map();
const MIDX={id:0,cno:1,off:2,Vol:3,V:4,B:5,I:6,N:7,lw:8,box:9,content:10,smooth:11,src:12,edge:13,prim:14,maxE:15,minE:16,cent:17,mult:18,srcCount:19};
const LARGE_GRID_SIDE_LIMIT=100, LARGE_GRID_CELL_LIMIT=100*100, DRAW_GRID_PAD=34, DEFAULT_DISPLAY_LIMIT=100;

const HELP_TEXT={"Record ID": "<p><strong>What it is.</strong> The database's internal record identifier, written as LP000001, LP000002, and so on. It identifies a stored row before AGL2(Z)-equivalent rows are merged in the result list.</p><p><strong>How it is assigned.</strong> The ID is read from the metadata layer. Records may come from small-polytopes, LDP, or both; equivalent records can be merged after search, but the displayed ID remains the representative stored record.</p>", "Source": "<p><strong>What it is.</strong> The provenance of the stored polygon record. In this build the source category is small-polytopes, LDP, both, or drawn for a temporary polygon made in the drawing panel.</p><p><strong>How it is used.</strong> Source filtering is applied at metadata level before expensive vertex loading. It does not change the polygon invariants, only which records are considered.</p>", "Display limit": "<p><strong>What it is.</strong> The maximum number of raw matching records to scan/render from the current search. The default is 100.</p><p><strong>How it is used.</strong> The limit is applied before exact AGL2(Z) merging of equivalent polygons. If the limit is reached, the interface warns that further records may also match and asks the user to raise the limit for a fuller search.</p>", "Normalized volume": "<p><strong>What it is.</strong> The normalized lattice area of the polygon. For a two-dimensional lattice polygon this is twice the usual Euclidean area.</p><p><strong>How it is calculated.</strong> If the vertices are cyclically ordered, the app uses the shoelace determinant formula: \\(\\operatorname{Vol}(P)=2\\operatorname{Area}(P)=\\left|\\sum_i\\det(v_i,v_{i+1})\\right|\\). In the associated polarized toric surface this equals \\(L^2\\) and the projective degree.</p>", "Euclidean area": "<p><strong>What it is.</strong> The ordinary planar area of the polygon measured in unit lattice squares.</p><p><strong>How it is calculated.</strong> It is half of the normalized volume: \\(\\operatorname{Area}(P)=\\operatorname{Vol}(P)/2\\). Fractional input such as 3/2 is accepted.</p>", "Vertices": "<p><strong>What it is.</strong> Vertices are the corner points of the convex hull that cannot be removed without changing the polygon. They are lattice points in \\(M\\cong\\mathbb Z^2\\).</p><p><strong>How it is calculated.</strong> The app forms the convex hull of the stored lattice points/vertices and counts its extreme points. Collinear non-corner boundary lattice points are not counted as vertices.</p>", "Number of vertices": "<p><strong>What it is.</strong> The number \\(V\\) of extreme lattice points of the convex polygon.</p><p><strong>How it is calculated.</strong> It is the length of the cyclic vertex list after taking the convex hull and removing collinear non-corner points. For a complete toric surface with this normal fan, the number of invariant divisors is also \\(V\\).</p>", "Boundary points": "<p><strong>What it is.</strong> The number \\(B\\) of lattice points lying on the boundary \\(\\partial P\\), including vertices and non-vertex edge lattice points.</p><p><strong>How it is calculated.</strong> For each edge vector \\(u_i=(a_i,b_i)\\), its lattice length is \\(\\ell_i=\\gcd(|a_i|,|b_i|)\\). The boundary count is \\(B=\\sum_i\\ell_i\\).</p>", "Interior points": "<p><strong>What it is.</strong> The number \\(I\\) of lattice points strictly inside the polygon.</p><p><strong>How it is calculated.</strong> In dimension two the app uses Pick's theorem: \\(I=\\operatorname{Area}(P)-B/2+1=(\\operatorname{Vol}(P)-B+2)/2\\). Algebraically this is the sectional arithmetic genus of a generic curve with Newton polygon \\(P\\).</p>", "Total lattice points": "<p><strong>What it is.</strong> The total number \\(N=\\#(P\\cap M)\\) of lattice points in the polygon, including boundary and interior points.</p><p><strong>How it is calculated.</strong> The app uses \\(N=B+I\\). In the toric embedding, \\(N=h^0(X_P,L_P)\\), so the associated projective space is \\(\\mathbb P^{N-1}\\).</p>", "Lattice points N, dim, codim": "<p><strong>What it is.</strong> A compact display of \\(N\\), the projective linear-system dimension, and the codimension of the toric surface embedding.</p><p><strong>How it is calculated.</strong> The values are \\(N=\\#(P\\cap M)\\), \\(\\dim |L|=N-1\\), and for a surface in \\(\\mathbb P^{N-1}\\), \\(\\operatorname{codim}=N-3\\).</p>", "Boundary / interior lattice points": "<p><strong>What it is.</strong> The pair \\(B/I\\), recording boundary and strict interior lattice-point counts.</p><p><strong>How it is calculated.</strong> \\(B=\\sum_i\\gcd(|\\Delta x_i|,|\\Delta y_i|)\\), and \\(I=(\\operatorname{Vol}(P)-B+2)/2\\) by Pick's theorem.</p>", "Codegree": "<p><strong>What it is.</strong> The Ehrhart codegree is the smallest positive integer \\(k\\) such that \\((kP)^\\circ\\cap M\\neq\\varnothing\\).</p><p><strong>How it is calculated.</strong> For lattice polygons the app uses the dimension-two rule visible from interior counts: codegree 1 if \\(I>0\\); otherwise codegree 2 for lattice polygons with enough boundary lattice points, and codegree 3 for unimodular-simplex type cases. The Ehrhart degree is \\(3-\\operatorname{codeg}(P)\\).</p>", "Degree": "<p><strong>What it is.</strong> The degree of the \\(h^*\\)-polynomial, not to be confused with projective degree \\(L^2\\).</p><p><strong>How it is calculated.</strong> In dimension two, \\(\\deg h^*=3-\\operatorname{codeg}(P)\\). The app computes codegree from whether dilates have interior lattice points.</p>", "h*-coefficient h1": "<p><strong>What it is.</strong> The first nontrivial coefficient of the Ehrhart \\(h^*\\)-vector of a lattice polygon.</p><p><strong>How it is calculated.</strong> For polygons, \\(h^*(t)=1+h_1^*t+h_2^*t^2\\) with \\(h_1^*=N-3\\) and \\(h_2^*=I\\).</p>", "h*-coefficient h2": "<p><strong>What it is.</strong> The second coefficient of the Ehrhart \\(h^*\\)-vector. In dimension two it equals the number of interior lattice points.</p><p><strong>How it is calculated.</strong> The app uses \\(h_2^*=I\\), with \\(I\\) computed from Pick's theorem.</p>", "max h*-coefficient": "<p><strong>What it is.</strong> The maximum entry of the three-term vector \\((1,h_1^*,h_2^*)\\).</p><p><strong>How it is calculated.</strong> The app computes \\(\\max(1,N-3,I)\\). This is mainly a quick shape filter for the Ehrhart numerator.</p>", "sum of h*-coefficients": "<p><strong>What it is.</strong> The sum of all coefficients of the \\(h^*\\)-vector.</p><p><strong>How it is calculated.</strong> For lattice polytopes, this sum equals normalized volume. Here \\(1+h_1^*+h_2^*=\\operatorname{Vol}(P)\\).</p>", "Ehrhart value #(kP ∩ M)": "<p><strong>What it is.</strong> The number of lattice points in the integer dilation \\(kP\\).</p><p><strong>How it is calculated.</strong> For a lattice polygon, \\(L_P(k)=\\#(kP\\cap M)=\\operatorname{Area}(P)k^2+(B/2)k+1=(\\operatorname{Vol}(P)k^2+B k+2)/2\\).</p>", "Has interior lattice point": "<p><strong>What it is.</strong> Whether \\(P\\) contains at least one lattice point not lying on the boundary.</p><p><strong>How it is calculated.</strong> The app checks whether \\(I>0\\), where \\(I=(\\operatorname{Vol}(P)-B+2)/2\\).</p>", "Palindromic h*-vector": "<p><strong>What it is.</strong> Whether the Ehrhart numerator is symmetric. For a polygon this means \\((1,h_1^*,h_2^*)\\) reads the same forward and backward.</p><p><strong>How it is calculated.</strong> Since the first coefficient is 1, palindromicity is equivalent here to \\(h_2^*=I=1\\). This is used as a reflexive/Gorenstein signal after a suitable interior-origin choice, not by itself as a proof that a displayed pointed polygon is reflexive.</p>", "Unimodal h*-vector": "<p><strong>What it is.</strong> Whether the \\(h^*\\)-entries rise and then fall without a second rise.</p><p><strong>How it is calculated.</strong> For \\((1,h_1^*,h_2^*)\\), the app checks \\(1\\le h_1^*\\) and \\(h_1^*\\ge h_2^*\\).</p>", "Log-concave h*-vector": "<p><strong>What it is.</strong> Whether the \\(h^*\\)-vector satisfies the discrete log-concavity inequality.</p><p><strong>How it is calculated.</strong> For \\((1,h_1^*,h_2^*)\\), the condition is \\((h_1^*)^2\\ge h_2^*\\).</p>", "Lattice width": "<p><strong>What it is.</strong> The minimum thickness of \\(P\\) measured in a primitive dual-lattice direction.</p><p><strong>How it is calculated.</strong> For a primitive covector \\(m\\in N=\\operatorname{Hom}(M,\\mathbb Z)\\), \\(\\operatorname{width}_m(P)=\\max_{p\\in P}\\langle m,p\\rangle-\\min_{p\\in P}\\langle m,p\\rangle\\). The lattice width is \\(\\min_m\\operatorname{width}_m(P)\\). In this build candidate directions are generated from bounded dual arrangements.</p>", "Minimum bounding square": "<p><strong>What it is.</strong> The smallest displayed \\(n\\times n\\) square size after applying affine unimodular coordinate changes.</p><p><strong>How it is calculated.</strong> The app searches unimodular dual bases \\((m_1,m_2)\\) and minimizes \\(\\max(\\operatorname{width}_{m_1}(P),\\operatorname{width}_{m_2}(P))\\). Ties are broken by a narrower horizontal span and then deterministic vertex order.</p>", "Minimum displayed n×n square": "<p><strong>What it is.</strong> The square size used for the canonical display orientation, together with the chosen rectangle spans.</p><p><strong>How it is calculated.</strong> It is minimized over unimodular coordinate systems. The score is based first on the larger span, then the two spans, area of the display box, sum of spans, and finally a lexicographic vertex key.</p>", "Minimum display x-span": "<p><strong>What it is.</strong> The horizontal span of the selected minimum-square display, after applying an allowed unimodular transformation.</p><p><strong>How it is calculated.</strong> Once the minimum-square coordinate basis is chosen, the app uses \\(\\max x-\\min x\\) of the transformed vertices.</p>", "Minimum display y-span": "<p><strong>What it is.</strong> The vertical span of the selected minimum-square display.</p><p><strong>How it is calculated.</strong> Once the minimum-square coordinate basis is chosen, the app uses \\(\\max y-\\min y\\) of the transformed vertices.</p>", "Minimum display box product": "<p><strong>What it is.</strong> The area of the axis-aligned display rectangle in the selected minimum-square coordinate system.</p><p><strong>How it is calculated.</strong> The app multiplies the selected display spans: \\((\\max x-\\min x)(\\max y-\\min y)\\).</p>", "Dilation factor": "<p><strong>What it is.</strong> The largest lattice dilation content visible after translating the polygon by one of its vertices.</p><p><strong>How it is calculated.</strong> If \\(v_0\\) is an anchor vertex, the factor is \\(\\gcd\\{(v_i-v_0)_1,(v_i-v_0)_2: i\\}\\). A value greater than 1 means \\(P=v_0+dP'\\) for a primitive lattice polygon \\(P'\\).</p>", "Lattice dilation factor": "<p><strong>What it is.</strong> The same primitive-content/dilation factor displayed in the opened record.</p><p><strong>How it is calculated.</strong> It is the gcd of all coordinate differences from an anchor vertex. Dividing those differences by the factor gives the primitive polygon.</p>", "Primitive polygon normalized volume": "<p><strong>What it is.</strong> The normalized volume after removing the largest lattice dilation factor from \\(P\\).</p><p><strong>How it is calculated.</strong> If \\(P=v_0+dP'\\), then the primitive polygon is \\(P'=(P-v_0)/d\\), and \\(\\operatorname{Vol}(P')=\\operatorname{Vol}(P)/d^2\\).</p>", "Primitive polygon boundary points": "<p><strong>What it is.</strong> The boundary lattice-point count of the primitive polygon obtained after removing lattice dilation.</p><p><strong>How it is calculated.</strong> The app forms \\(P'=(P-v_0)/d\\), then recomputes \\(B'=\\sum_i\\gcd(|\\Delta x_i'|,|\\Delta y_i'|)\\).</p>", "Width in direction (a,b)": "<p><strong>What it is.</strong> The width of \\(P\\) in the specific dual direction \\((a,b)\\).</p><p><strong>How it is calculated.</strong> The app evaluates \\(a x+b y\\) on all vertices and returns \\(\\max_P(ax+by)-\\min_P(ax+by)\\). The zero direction is ignored.</p>", "Area centroid x": "<p><strong>What it is.</strong> The x-coordinate of the ordinary area centroid of the filled polygon.</p><p><strong>How it is calculated.</strong> The app uses the polygon centroid formula from the shoelace determinants: \\(C_x=\\frac{1}{6A}\\sum_i(x_i+x_{i+1})\\det(v_i,v_{i+1})\\), with signed Euclidean area \\(A\\).</p>", "Area centroid y": "<p><strong>What it is.</strong> The y-coordinate of the ordinary area centroid of the filled polygon.</p><p><strong>How it is calculated.</strong> The app uses \\(C_y=\\frac{1}{6A}\\sum_i(y_i+y_{i+1})\\det(v_i,v_{i+1})\\), with signed Euclidean area \\(A\\).</p>", "All lattice-point centroid x": "<p><strong>What it is.</strong> The x-coordinate of the average of all lattice points in \\(P\\).</p><p><strong>How it is calculated.</strong> The app enumerates \\(P\\cap M\\) and computes \\(\\frac{1}{N}\\sum_{p\\in P\\cap M}p_x\\).</p>", "All lattice-point centroid y": "<p><strong>What it is.</strong> The y-coordinate of the average of all lattice points in \\(P\\).</p><p><strong>How it is calculated.</strong> The app enumerates \\(P\\cap M\\) and computes \\(\\frac{1}{N}\\sum_{p\\in P\\cap M}p_y\\).</p>", "Boundary centroid x": "<p><strong>What it is.</strong> The x-coordinate of the average boundary lattice point.</p><p><strong>How it is calculated.</strong> The app enumerates \\(\\partial P\\cap M\\) and averages the x-coordinates.</p>", "Boundary centroid y": "<p><strong>What it is.</strong> The y-coordinate of the average boundary lattice point.</p><p><strong>How it is calculated.</strong> The app enumerates \\(\\partial P\\cap M\\) and averages the y-coordinates.</p>", "Interior centroid x": "<p><strong>What it is.</strong> The x-coordinate of the average strict interior lattice point.</p><p><strong>How it is calculated.</strong> The app enumerates \\(P^\\circ\\cap M\\) and averages the x-coordinates. If \\(I=0\\), this value is not defined and interior-centroid filters do not match.</p>", "Interior centroid y": "<p><strong>What it is.</strong> The y-coordinate of the average strict interior lattice point.</p><p><strong>How it is calculated.</strong> The app enumerates \\(P^\\circ\\cap M\\) and averages the y-coordinates. If \\(I=0\\), this value is not defined and interior-centroid filters do not match.</p>", "Primitive edges": "<p><strong>What it is.</strong> The number of edges whose lattice length is 1.</p><p><strong>How it is calculated.</strong> Each edge vector \\((a,b)\\) has length \\(\\gcd(|a|,|b|)\\). Primitive edges are those with length exactly 1.</p>", "Non-primitive edges": "<p><strong>What it is.</strong> The number of edges containing additional lattice points between their vertices.</p><p><strong>How it is calculated.</strong> It is \\(V-\\#\\{i:\\ell_i=1\\}\\), where \\(\\ell_i=\\gcd(|\\Delta x_i|,|\\Delta y_i|)\\).</p>", "Max edge length": "<p><strong>What it is.</strong> The largest lattice length among the edges of \\(P\\).</p><p><strong>How it is calculated.</strong> The app computes all \\(\\ell_i=\\gcd(|\\Delta x_i|,|\\Delta y_i|)\\) and takes the maximum.</p>", "Min edge length": "<p><strong>What it is.</strong> The smallest lattice length among the edges of \\(P\\).</p><p><strong>How it is calculated.</strong> The app computes all edge lengths \\(\\ell_i\\) and takes the minimum. This is also used as a local-positivity proxy in the algebraic section.</p>", "Max normal multiplicity": "<p><strong>What it is.</strong> The largest affine multiplicity among cones of the normal fan.</p><p><strong>How it is calculated.</strong> For adjacent primitive normal rays \\(\\nu_{i-1},\\nu_i\\), the cone multiplicity is \\(\\mu_i=|\\det(\\nu_{i-1},\\nu_i)|\\). The app takes the maximum of the \\(\\mu_i\\).</p>", "Min normal multiplicity": "<p><strong>What it is.</strong> The smallest affine multiplicity among cones of the normal fan.</p><p><strong>How it is calculated.</strong> The app computes \\(\\mu_i=|\\det(\\nu_{i-1},\\nu_i)|\\) for all adjacent normal rays and takes the minimum.</p>", "Number of singular cones": "<p><strong>What it is.</strong> The number of cones in the normal fan that are not smooth/unimodular.</p><p><strong>How it is calculated.</strong> A two-dimensional cone is smooth exactly when \\(\\mu_i=|\\det(\\nu_{i-1},\\nu_i)|=1\\). The count is the number of cones with \\(\\mu_i>1\\).</p>", "Edge length cycle": "<p><strong>What it is.</strong> The cyclic sequence of lattice edge lengths around the polygon.</p><p><strong>How it is calculated.</strong> The app computes \\(\\ell_i=\\gcd(|\\Delta x_i|,|\\Delta y_i|)\\) for each oriented edge, then stores a canonical cyclic sequence up to rotation and reversal.</p>", "Normal multiplicity cycle": "<p><strong>What it is.</strong> The cyclic sequence of normal-cone multiplicities around the polygon/fan.</p><p><strong>How it is calculated.</strong> For adjacent primitive normals the app computes \\(\\mu_i=|\\det(\\nu_{i-1},\\nu_i)|\\), then canonicalizes the sequence up to rotation and reversal.</p>", "Smooth fan": "<p><strong>What it is.</strong> Whether the normal fan defines a smooth complete toric surface.</p><p><strong>How it is calculated.</strong> The fan is smooth exactly when every adjacent pair of primitive rays is a unimodular basis, equivalently all \\(\\mu_i=1\\).</p>", "All edges primitive": "<p><strong>What it is.</strong> Whether every polygon edge has lattice length 1.</p><p><strong>How it is calculated.</strong> The app checks whether every \\(\\ell_i=\\gcd(|\\Delta x_i|,|\\Delta y_i|)\\) equals 1.</p>", "Reflexive/Gorenstein signal (h2*=1)": "<p><strong>What it is.</strong> A quick unpointed signal for possible two-dimensional reflexive/Gorenstein behavior.</p><p><strong>How it is calculated.</strong> The search uses \\(h_2^*=I\\), so the signal is yes when \\(I=1\\). Strict reflexivity also depends on choosing the unique interior point as origin and checking facet distances \\(h_i=1\\).</p>", "Picard rank ρ": "<p><strong>What it is.</strong> The Picard rank proxy of the complete toric surface associated with the normal fan.</p><p><strong>How it is calculated.</strong> For a complete toric surface with \\(V\\) rays and no rank correction from non-simplicial cones in dimension two, \\(\\rho=V-2\\). For singular surfaces this is displayed as a toric/class-group rank proxy.</p>", "Betti number b2": "<p><strong>What it is.</strong> The second Betti number proxy for the associated smooth complete toric surface.</p><p><strong>How it is calculated.</strong> In the smooth complete toric surface case, \\(b_2=\\rho=V-2\\). For singular records it is kept as a fan-combinatorial proxy.</p>", "Hodge number h11": "<p><strong>What it is.</strong> The \\(h^{1,1}\\) entry of the Hodge diamond in the smooth complete toric surface case.</p><p><strong>How it is calculated.</strong> For a smooth complete toric surface, \\(h^{1,1}=\\rho=V-2\\). The app suppresses the Hodge diamond for singular normal fans.</p>", "Euler characteristic c2": "<p><strong>What it is.</strong> The Euler characteristic / second Chern number proxy of the associated toric surface.</p><p><strong>How it is calculated.</strong> For a smooth complete toric surface, \\(c_2=e(X)=V\\), the number of torus fixed points/rays. The search metadata uses this fan-combinatorial value.</p>", "Second Chern number c2": "<p><strong>What it is.</strong> The topological second Chern number in the smooth toric surface interpretation.</p><p><strong>How it is calculated.</strong> In the smooth complete toric case \\(c_2=V\\). In singular cases the app labels it as a proxy rather than a resolved-surface invariant.</p>", "c1^2 / K^2 proxy": "<p><strong>What it is.</strong> A quick smooth-surface proxy for the square of the first Chern class, equivalently \\(K^2\\) up to sign convention.</p><p><strong>How it is calculated.</strong> For smooth complete toric surfaces, Noether's toric formula gives \\(c_1^2=K^2=12-V\\). The detailed toric section also computes \\((-K_X)^2\\) from the rational intersection matrix.</p>", "Signature proxy": "<p><strong>What it is.</strong> A smooth compact oriented four-manifold signature proxy for the associated toric surface.</p><p><strong>How it is calculated.</strong> For smooth complete toric surfaces, \\(\\sigma=(c_1^2-2c_2)/3=(12-V-2V)/3=4-V\\). The metadata filter uses an equivalent simple fan formula.</p>", "Centrally symmetric": "<p><strong>What it is.</strong> Whether the polygon is invariant under a half-turn about the center of its bounding lattice-point set.</p><p><strong>How it is calculated.</strong> The app checks that every lattice point \\(p\\in P\\cap M\\) is paired with \\(c-p\\), where \\(c\\) is determined by opposite bounding-box extremes. This is a fast exact test on the full lattice-point set.</p>", "Grid size": "<p><strong>What it is.</strong> The side length of the interactive lattice grid in the drawn-polygon search panel.</p><p><strong>How it is used.</strong> The grid is centered at the origin. Selected lattice points are replaced by their convex hull before the app attempts exact AGL2(Z) matching against the database.</p>", "Advanced search": "<p><strong>What it is.</strong> The expandable group of more specialized filters beyond the common metadata fields.</p><p><strong>How it is applied.</strong> Cheap metadata filters run first. Filters requiring exact vertices, centroids or primitive reduction are applied only after candidate rows are narrowed and vertex data are loaded.</p>", "Combinatorial / Ehrhart data": "<p><strong>What it is.</strong> Filters based on lattice-point enumeration, Pick's theorem, and Ehrhart/Hilbert-series data.</p><p><strong>How it is calculated.</strong> These quantities are derived from \\(V,B,I,N,\\operatorname{Vol}(P)\\) and the two-dimensional Ehrhart formulas.</p>", "Lattice / affine geometry": "<p><strong>What it is.</strong> Filters describing the polygon as an affine lattice object, independent of a chosen coordinate drawing up to AGL2(Z).</p><p><strong>How it is calculated.</strong> The app searches primitive dual directions, unimodular coordinate bases, centroids, and primitive dilation reductions from the vertex set.</p>", "Toric fan / singularities": "<p><strong>What it is.</strong> Filters coming from the normal fan of the polygon and its associated toric surface singularities.</p><p><strong>How it is calculated.</strong> Primitive outward normals are formed from edges; adjacent determinants give cone multiplicities, smoothness, and singular-cone counts.</p>", "Algebraic topology / surface proxies": "<p><strong>What it is.</strong> Quick invariants motivated by smooth compact toric surfaces, displayed as proxies when the fan is singular.</p><p><strong>How it is calculated.</strong> Most are functions of the number \\(V\\) of rays: \\(\\rho=b_2=h^{1,1}=V-2\\), \\(c_2=V\\), and the simple smooth-surface proxies for \\(c_1^2\\) and signature.</p>", "Symmetry / exact cycles": "<p><strong>What it is.</strong> Filters involving exact cyclic sequences and central symmetry.</p><p><strong>How it is calculated.</strong> Edge and multiplicity cycles are canonicalized up to rotation/reversal. Central symmetry is checked on the full lattice-point set.</p>", "Results": "<p><strong>What it is.</strong> The merged list of records matching the current search.</p><p><strong>How it is produced.</strong> The app first filters metadata, then loads vertices when needed, groups AGL2(Z)-equivalent polygons, and displays one representative card for each merged polygon class.</p>", "General search": "<p><strong>What it is.</strong> The main database query panel for stored lattice-polygon records.</p><p><strong>How it works.</strong> Each filter compares a computed or stored invariant using the selected relation. Empty fields are ignored.</p>", "Drawn polygon search": "<p><strong>What it is.</strong> A local drawing interface for selecting lattice points and searching for the convex hull in the database.</p><p><strong>How it works.</strong> The app computes the convex hull of selected points, then tests exact affine unimodular equivalence against metadata buckets and narrowed candidates.</p>", "Basic geometry": "<p><strong>What it is.</strong> The first summary block of core combinatorial and lattice-geometric invariants.</p><p><strong>How it is calculated.</strong> Values are recomputed in the browser from the displayed vertex list, so rotations/flips of the view do not change the invariant values.</p>", "Sources": "<p><strong>What it is.</strong> The source labels stored with the record, plus the compact source category used by search.</p><p><strong>How it is calculated.</strong> The app reads source labels from the record data. For merged result cards, source chips aggregate the categories of equivalent stored records.</p>", "Vol = L^2 = degree": "<p><strong>What it is.</strong> The normalized volume of \\(P\\), the self-intersection \\(L^2\\) of the polarizing line bundle, and the projective degree of \\(X_P\\subset\\mathbb P^{N-1}\\).</p><p><strong>How it is calculated.</strong> The app uses \\(L^2=\\operatorname{Vol}(P)=2\\operatorname{Area}(P)\\) from the shoelace determinant.</p>", "Automorphism group": "<p><strong>What it is.</strong> The finite group of affine unimodular transformations preserving the polygon.</p><p><strong>How it is calculated.</strong> The app searches maps \\(x\\mapsto Ax+b\\) with \\(A\\in GL_2(\\mathbb Z)\\), \\(\\det A=\\pm1\\), and \\(A(P)+b=P\\), then counts and classifies them.</p>", "Smooth / cone multiplicities": "<p><strong>What it is.</strong> A compact smoothness test for the normal fan and the list of cone multiplicities.</p><p><strong>How it is calculated.</strong> Multiplicities are \\(\\mu_i=|\\det(\\nu_{i-1},\\nu_i)|\\). The fan is smooth exactly when all \\(\\mu_i=1\\).</p>", "Normality / IDP": "<p><strong>What it is.</strong> Whether the polygon has the integer decomposition property (IDP), also called normality of the associated semigroup.</p><p><strong>How it is calculated.</strong> Every two-dimensional lattice polygon is normal, so the app displays yes without running a separate decomposition algorithm.</p>", "Symmetry group and point orbits": "<p><strong>What it is.</strong> The affine unimodular symmetry group together with its action on vertices and lattice points.</p><p><strong>How it is calculated.</strong> After finding all automorphisms \\(x\\mapsto Ax+b\\), the app partitions vertices, boundary points, interior points and all lattice points into orbits under the group action.</p>", "Group type": "<p><strong>What it is.</strong> A coarse name for the finite affine symmetry group: trivial, cyclic/orientation-preserving, C2, or dihedral-type.</p><p><strong>How it is calculated.</strong> The app counts automorphisms and the number with determinant +1 and -1, then assigns the displayed coarse type.</p>", "Order": "<p><strong>What it is.</strong> The number of elements in the displayed group or finite set.</p><p><strong>How it is calculated.</strong> For symmetry groups it is the number of affine unimodular self-maps found exactly. In other contexts it means the size/order explicitly stated by that row.</p>", "Orientation preserving / reversing": "<p><strong>What it is.</strong> The split of polygon automorphisms according to determinant sign.</p><p><strong>How it is calculated.</strong> Each automorphism has linear part \\(A\\). The app counts those with \\(\\det A=+1\\) and those with \\(\\det A=-1\\).</p>", "Vertex orbits": "<p><strong>What it is.</strong> The partition of polygon vertices under the automorphism group.</p><p><strong>How it is calculated.</strong> Vertices are joined into the same orbit if an automorphism maps one to the other.</p>", "Boundary-point orbits": "<p><strong>What it is.</strong> The partition of boundary lattice points under polygon symmetries.</p><p><strong>How it is calculated.</strong> The app enumerates \\(\\partial P\\cap M\\) and applies every automorphism to form orbit classes.</p>", "Interior-point orbits": "<p><strong>What it is.</strong> The partition of strict interior lattice points under polygon symmetries.</p><p><strong>How it is calculated.</strong> The app enumerates \\(P^\\circ\\cap M\\) and groups points connected by an automorphism.</p>", "All lattice-point orbit sizes": "<p><strong>What it is.</strong> The sizes of orbits on the full lattice-point set \\(P\\cap M\\).</p><p><strong>How it is calculated.</strong> After orbit grouping, the app lists the cardinality of each orbit rather than all its coordinates.</p>", "Elements": "<p><strong>What it is.</strong> The affine unimodular transformations in the symmetry group, displayed as matrices and translations.</p><p><strong>How it is calculated.</strong> Each element has the form \\(x\\mapsto Ax+b\\). The app lists a capped sample when the group is large.</p>", "Ehrhart, Hilbert and adjunction data": "<p><strong>What it is.</strong> The section translating lattice-point counts into Ehrhart polynomials, Hilbert series, and adjunction data for the polarized toric surface.</p><p><strong>How it is calculated.</strong> It uses \\(\\operatorname{Vol}(P),B,I,N\\), Pick's theorem, Ehrhart reciprocity, and the identity \\(h^0(X,kL)=\\#(kP\\cap M)\\).</p>", "Ehrhart polynomial": "<p><strong>What it is.</strong> The polynomial counting lattice points in dilates \\(kP\\).</p><p><strong>How it is calculated.</strong> \\(L_P(k)=(\\operatorname{Vol}(P)k^2+B k+2)/2\\), using normalized volume and boundary count.</p>", "Interior Ehrhart polynomial": "<p><strong>What it is.</strong> The polynomial counting strict interior lattice points of \\(kP\\).</p><p><strong>How it is calculated.</strong> By Ehrhart reciprocity in dimension two: \\(L_{P^\\circ}(k)=(\\operatorname{Vol}(P)k^2-B k+2)/2\\) for positive \\(k\\).</p>", "Ehrhart / Hilbert series": "<p><strong>What it is.</strong> The generating function for \\(\\#(kP\\cap M)\\), also the Hilbert series of the section ring of \\((X_P,L_P)\\).</p><p><strong>How it is calculated.</strong> In dimension two, \\(\\sum_{k\\ge0}L_P(k)t^k=(1+h_1^*t+h_2^*t^2)/(1-t)^3\\), with \\(h_1^*=N-3\\) and \\(h_2^*=I\\).</p>", "Interior-count generating function": "<p><strong>What it is.</strong> The generating function for strict interior lattice-point counts in dilates.</p><p><strong>How it is calculated.</strong> It is derived from Ehrhart reciprocity and the same \\(h^*\\)-data: numerator \\(h_2^*t+h_1^*t^2+t^3\\) over \\((1-t)^3\\).</p>", "h^*-vector and symmetry": "<p><strong>What it is.</strong> The Ehrhart numerator vector and whether it is symmetric.</p><p><strong>How it is calculated.</strong> The app displays \\((1,N-3,I)\\). Symmetry is checked by comparing the first and last entries, so in polygons it is equivalent to \\(I=1\\).</p>", "h^* unimodality / log-concavity": "<p><strong>What it is.</strong> Two shape conditions on the Ehrhart numerator coefficients.</p><p><strong>How it is calculated.</strong> For \\((1,h_1,h_2)\\), unimodality is \\(1\\le h_1\\ge h_2\\); log-concavity is \\(h_1^2\\ge h_2\\).</p>", "Codegree / h^*-degree": "<p><strong>What it is.</strong> The pair of Ehrhart codegree and \\(h^*\\)-degree.</p><p><strong>How it is calculated.</strong> The codegree is the first dilate with an interior lattice point, and \\(\\deg h^*=3-\\operatorname{codeg}(P)\\).</p>", "Ehrhart roots": "<p><strong>What it is.</strong> The complex or real roots of the quadratic Ehrhart polynomial.</p><p><strong>How it is calculated.</strong> The app solves \\(\\operatorname{Vol}(P)k^2+B k+2=0\\) exactly when possible and displays a radical expression.</p>", "Toric surface, divisors and class group": "<p><strong>What it is.</strong> The section interpreting the normal fan as a complete toric surface and listing divisor/class-group data.</p><p><strong>How it is calculated.</strong> Primitive outward normals give rays. The app computes cone determinants, class-group cokernels, support constants, rational intersection numbers and fan-based Fano tests.</p>", "Normal fan rays": "<p><strong>What it is.</strong> The primitive outward normal vectors to the edges of \\(P\\). They are the rays of the normal fan.</p><p><strong>How it is calculated.</strong> For each oriented edge vector \\((dx,dy)\\), the primitive outward normal is proportional to \\((dy,-dx)\\) divided by \\(\\gcd(|dx|,|dy|)\\).</p>", "Cone multiplicities / smoothness": "<p><strong>What it is.</strong> The determinant multiplicities of two-dimensional cones in the normal fan and the resulting smoothness status.</p><p><strong>How it is calculated.</strong> For adjacent rays \\(\\nu_{i-1},\\nu_i\\), \\(\\mu_i=|\\det(\\nu_{i-1},\\nu_i)|\\). Smoothness means all \\(\\mu_i=1\\).</p>", "Local cone normal forms": "<p><strong>What it is.</strong> A local cyclic-quotient normal form for each fan cone.</p><p><strong>How it is calculated.</strong> The app reduces adjacent primitive rays to a Hermite/quotient description equivalent to a two-dimensional toric cyclic quotient \\(1/r(1,a)\\).</p>", "K_X Cartier index": "<p><strong>What it is.</strong> The smallest positive integer making the canonical divisor Cartier in the toric sense.</p><p><strong>How it is calculated.</strong> Locally, the Gorenstein/Cartier index is computed from adjacent normal cones. The global index is the least common multiple over all cones.</p>", "Cartier divisor lattice signal": "<p><strong>What it is.</strong> A diagnostic for whether the polarizing support data are integral Cartier data on the fan.</p><p><strong>How it is calculated.</strong> The app solves local linear support equations on adjacent cones and checks whether the resulting Cartier data are integral across cones.</p>", "Class group": "<p><strong>What it is.</strong> The toric Weil divisor class group of the complete fan, including displayed torsion order when present.</p><p><strong>How it is calculated.</strong> The class group is the cokernel of \\(M\\to\\mathbb Z^r\\), \\(m\\mapsto(\\langle m,\\nu_i\\rangle)_i\\). The app computes rank \\(r-2\\) and torsion from the ray matrix.</p>", "Rational class basis": "<p><strong>What it is.</strong> A chosen rational basis for the free part of \\(\\operatorname{Cl}(X)_\\mathbb Q\\).</p><p><strong>How it is calculated.</strong> The app selects independent divisor classes after quotienting by principal divisor relations. It is a computational basis, not a canonical mathematical choice.</p>", "Picard rank / Cox variables": "<p><strong>What it is.</strong> The rank proxy of the divisor class group and the number of homogeneous Cox coordinates.</p><p><strong>How it is calculated.</strong> For a complete toric surface with \\(V\\) rays, the rank is \\(V-2\\), and there is one Cox variable for each ray/divisor, so \\(V\\) Cox variables.</p>", "Fano index proxy": "<p><strong>What it is.</strong> A divisibility diagnostic for the anticanonical class in the displayed class group basis.</p><p><strong>How it is calculated.</strong> The app expresses \\(-K_X=\\sum_iD_i\\) in the rational class basis and checks common divisibility in the free part together with recorded torsion order.</p>", "Polarizing divisor": "<p><strong>What it is.</strong> The torus-invariant divisor \\(L_P\\) whose polytope is \\(P\\).</p><p><strong>How it is calculated.</strong> For normal rays \\(\\nu_i\\), support constants are \\(h_i=\\max_{p\\in P}\\langle\\nu_i,p\\rangle\\). The divisor is displayed as \\(L_P=\\sum_i h_iD_i\\), up to the sign convention used by the fan/polytope dictionary.</p>", "Anticanonical divisor": "<p><strong>What it is.</strong> The toric anticanonical divisor.</p><p><strong>How it is calculated.</strong> For a toric variety, \\(-K_X=\\sum_iD_i\\), the sum of all invariant prime divisors.</p>", "Vol = L^2 = degree; B=(-K_X)·L": "<p><strong>What it is.</strong> The two fundamental intersection numbers of the polarized toric surface.</p><p><strong>How it is calculated.</strong> The app uses \\(L^2=\\operatorname{Vol}(P)\\) and \\((-K_X)\\cdot L=B\\), where \\(B\\) is the boundary lattice-point count.</p>", "(-K_X)^2": "<p><strong>What it is.</strong> The self-intersection of the anticanonical divisor on the toric surface, possibly rational for singular fans.</p><p><strong>How it is calculated.</strong> The app builds the rational invariant-divisor intersection matrix and evaluates \\(\\left(\\sum_iD_i\\right)^2\\).</p>", "Anti-canonical nef/ample test": "<p><strong>What it is.</strong> A toric test for whether \\(-K_X\\) is nef or ample on invariant curves.</p><p><strong>How it is calculated.</strong> On a toric surface, invariant curves generate the Mori cone. The app computes \\((-K_X)\\cdot D_i\\); nonnegative values indicate nef, positive values indicate ample in the toric test.</p>", "Nef / ample inequalities": "<p><strong>What it is.</strong> The inequalities cutting out the toric nef cone in the displayed divisor coordinates.</p><p><strong>How it is calculated.</strong> The app computes intersection conditions \\(L\\cdot D_i\\ge0\\) against all invariant curves. Strict positivity is the corresponding toric ample signal.</p>", "Smooth Noether check": "<p><strong>What it is.</strong> A consistency check against the Noether formula in the smooth complete toric surface case.</p><p><strong>How it is calculated.</strong> For smooth toric surfaces, \\(K^2+c_2=12\\). The app compares computed \\((-K_X)^2\\) and \\(c_2=V\\).</p>", "L·D_i / edge lengths": "<p><strong>What it is.</strong> The intersections of the polarizing divisor with invariant curves, listed in the same order as edges.</p><p><strong>How it is calculated.</strong> In the toric polygon dictionary, \\(L\\cdot D_i\\) equals the lattice length \\(\\ell_i\\) of the corresponding edge.</p>", "Invariant divisor self-intersections": "<p><strong>What it is.</strong> The self-intersection numbers of torus-invariant divisors \\(D_i\\).</p><p><strong>How it is calculated.</strong> For a simplicial toric surface, \\(D_i^2=-\\det(\\nu_{i-1},\\nu_{i+1})/(\\det(\\nu_{i-1},\\nu_i)\\det(\\nu_i,\\nu_{i+1}))\\).</p>", "Algebraic geometry and curve-counting data": "<p><strong>What it is.</strong> The section for projective embedding, adjunction, Newton-curve geometry, Severi dimensions, and period computations.</p><p><strong>How it is calculated.</strong> It combines toric line bundle identities, interior polygons, lattice width, edge-length positivity proxies, and optional constant-term period calculations.</p>", "Projective embedding": "<p><strong>What it is.</strong> The toric surface embedded by the complete linear system of the polygon.</p><p><strong>How it is calculated.</strong> The lattice points \\(P\\cap M\\) give monomial sections of \\(L_P\\). Hence \\(X_P\\) embeds as \\(X_P\\subset\\mathbb P^{N-1}\\). The embedding line bundle is the polarizing divisor \\(L_P\\) determined by the support constants of \\(P\\).</p>", "Polarizing / canonical divisor": "<p><strong>What it is.</strong> The line bundle/divisor defining the embedding and the canonical divisor of the toric surface.</p><p><strong>How it is calculated.</strong> The app writes \\(L=\\sum h_iD_i\\) from support constants \\(h_i\\), while \\(K_X=-\\sum_iD_i\\). These are displayed in the invariant-divisor basis.</p>", "N, linear-system dim, codim": "<p><strong>What it is.</strong> The number of monomial sections, the dimension of the complete linear system, and the embedding codimension.</p><p><strong>How it is calculated.</strong> \\(N=\\#(P\\cap M)\\), \\(\\dim |L|=N-1\\), and because \\(X_P\\) is a surface in \\(\\mathbb P^{N-1}\\), \\(\\operatorname{codim}=N-3\\).</p>", "Sectional arithmetic genus": "<p><strong>What it is.</strong> The arithmetic genus of a generic curve in the linear system \\(|L|\\).</p><p><strong>How it is calculated.</strong> For toric surfaces/Newton polygons, \\(p_a(L)=I\\), the number of interior lattice points of \\(P\\).</p>", "Adjunction check": "<p><strong>What it is.</strong> A verification of the genus using the surface adjunction formula.</p><p><strong>How it is calculated.</strong> The app checks \\(p_a=1+(L^2+K_X\\cdot L)/2\\). Since \\(L^2=\\operatorname{Vol}(P)\\) and \\((-K_X)\\cdot L=B\\), this equals \\((\\operatorname{Vol}(P)-B+2)/2=I\\).</p>", "Adjoint lattice points": "<p><strong>What it is.</strong> The dimension of sections of \\(K_X+L\\), equivalently lattice points of the adjoint/interior polygon.</p><p><strong>How it is calculated.</strong> The toric adjunction dictionary gives \\(h^0(X,K_X+L)=\\#(P^\\circ\\cap M)=I\\).</p>", "Adjoint depth": "<p><strong>What it is.</strong> The number of nontrivial times one can pass to the interior/adjoint polygon before the process stops.</p><p><strong>How it is calculated.</strong> The app repeatedly replaces \\(P\\) by the convex hull of \\(P^\\circ\\cap M\\) and counts the levels that remain two-dimensional lattice polygons.</p>", "Canonical polygon type": "<p><strong>What it is.</strong> A description of the polygon formed by interior lattice points and its curve-theoretic role.</p><p><strong>How it is calculated.</strong> The app forms the convex hull of \\(P^\\circ\\cap M\\). Empty, one-point, segment, and two-dimensional cases are classified separately.</p>", "Curve type / gonality signal": "<p><strong>What it is.</strong> A heuristic summary of the generic Newton curve type and expected low-degree maps.</p><p><strong>How it is calculated.</strong> It uses genus \\(I\\), lattice width, and special small-genus/width cases as a signal. It is not a full Brill-Noether computation.</p>", "Lattice-width gonality input": "<p><strong>What it is.</strong> The lattice width used as an expected gonality or upper-bound signal for curves with Newton polygon \\(P\\).</p><p><strong>How it is calculated.</strong> Width directions define projections of the Newton polygon; such projections often produce pencils on the curve. The displayed number is the previously computed lattice width.</p>", "Width spectrum": "<p><strong>What it is.</strong> A compact count/sample of low-width primitive directions near the minimum lattice width.</p><p><strong>How it is calculated.</strong> The app enumerates primitive dual directions with width at most \\(\\operatorname{lw}(P)+3\\), groups them by width, and lists a sample.</p>", "Minimum-width slice counts": "<p><strong>What it is.</strong> The distribution of lattice points in slices perpendicular to a minimum-width direction.</p><p><strong>How it is calculated.</strong> For a chosen minimum direction \\(m\\), the app groups lattice points by \\(\\langle m,p\\rangle\\) and reports slice counts.</p>", "Derived Clifford input": "<p><strong>What it is.</strong> A rough input for Clifford-index style curve diagnostics.</p><p><strong>How it is calculated.</strong> For genus at least 2, the app displays \\(\\max(0,\\operatorname{lw}(P)-2)\\) as a lattice-width-derived signal, not a theorem-level certificate in all special cases.</p>", "δ-very ampleness proxy": "<p><strong>What it is.</strong> A local-positivity proxy related to whether the line bundle separates small subschemes.</p><p><strong>How it is calculated.</strong> The app checks the minimum lattice edge length. The current heuristic marks stronger positivity when all edge lengths are at least 3.</p>", "Expected Severi dimensions": "<p><strong>What it is.</strong> Expected dimensions for Severi-type families of curves of different geometric genera in \\(|L|\\).</p><p><strong>How it is calculated.</strong> The app uses the standard expected dimension pattern from the linear system and genus drop; it is a dimension count, not an enumerative proof.</p>", "Secondary polytope dimension proxy": "<p><strong>What it is.</strong> A quick proxy for the dimension of the space controlling regular subdivisions/triangulations of the point configuration.</p><p><strong>How it is calculated.</strong> For a planar point configuration with \\(N\\) points, the displayed proxy is \\(N-3\\).</p>", "Tropical fixed-polygon proxy": "<p><strong>What it is.</strong> A reminder of the genus input and the need for unimodular subdivisions in tropical curve counts.</p><p><strong>How it is calculated.</strong> The app uses genus \\(I\\). It does not enumerate all tropical curves or all unimodular subdivisions by default.</p>", "One-node Severi number (conditional)": "<p><strong>What it is.</strong> A conditional one-node count using the universal node-polynomial expression for sufficiently ample smooth toric surfaces.</p><p><strong>How it is calculated.</strong> When the fan is smooth, the app displays \\(3L^2+2LK+c_2=3\\operatorname{Vol}(P)-2B+V\\), with a warning that transversality/ample hypotheses are required.</p>", "Minkowski, Cayley and convex-geometric data": "<p><strong>What it is.</strong> The section for decomposition, Cayley structures, zonotopes, and edge-direction diagnostics.</p><p><strong>How it is calculated.</strong> It uses exact lattice quotient tests, width-one projections, central symmetry tests, and edge-direction combinatorics.</p>", "Width-one Cayley structure": "<p><strong>What it is.</strong> Whether the polygon has lattice width one, a basic Cayley/prism-like signal.</p><p><strong>How it is calculated.</strong> The app checks whether \\(\\operatorname{lw}(P)=1\\).</p>", "Cayley projection directions": "<p><strong>What it is.</strong> Primitive directions in which the polygon has width one.</p><p><strong>How it is calculated.</strong> The app enumerates primitive dual directions \\(m\\) and lists those with \\(\\operatorname{width}_m(P)=1\\).</p>", "Minimum-width directions": "<p><strong>What it is.</strong> Primitive dual directions that achieve the lattice width.</p><p><strong>How it is calculated.</strong> After computing \\(\\operatorname{lw}(P)\\), the app lists sampled directions \\(m\\) with \\(\\operatorname{width}_m(P)=\\operatorname{lw}(P)\\).</p>", "Homothetic decompositions": "<p><strong>What it is.</strong> Possible decompositions coming from a nontrivial lattice dilation of the whole polygon.</p><p><strong>How it is calculated.</strong> If the content is \\(d\\), every divisor of \\(d\\) gives a homothetic scaling signal \\(P=v_0+dP'\\).</p>", "Exact segment summands": "<p><strong>What it is.</strong> Decompositions of the form \\(P=Q+[0,u]\\) for a lattice segment \\([0,u]\\).</p><p><strong>How it is calculated.</strong> The app computes exact quotients \\(Q=P\\cap(P-u)\\), takes their convex hull, and verifies \\(Q+[0,u]=P\\) by exact polygon equality.</p>", "Centrally symmetric zonotope decomposition": "<p><strong>What it is.</strong> Whether the polygon is detected as a centrally symmetric zonotope generated by segments.</p><p><strong>How it is calculated.</strong> The app first checks central symmetry and even number of edges, then reads generators from half of the cyclic edge vectors.</p>", "Parallel edge classes": "<p><strong>What it is.</strong> The number of distinct parallel edge-direction classes.</p><p><strong>How it is calculated.</strong> Edge directions are made primitive and identified up to sign; the number of resulting classes is displayed.</p>", "Lattice diameter": "<p><strong>What it is.</strong> The largest lattice step distance between two lattice points of \\(P\\).</p><p><strong>How it is calculated.</strong> For all pairs \\(p,q\\in P\\cap M\\), the app computes \\(\\gcd(|q_x-p_x|,|q_y-p_y|)\\) and takes the maximum.</p>", "Primitive edge directions": "<p><strong>What it is.</strong> The primitive direction vector of each edge, up to the chosen cyclic orientation.</p><p><strong>How it is calculated.</strong> Each edge vector is divided by its gcd lattice length.</p>", "Fan and edge-direction sketches": "<p><strong>What it is.</strong> A visual comparison of outward normal rays and edge directions.</p><p><strong>How it is calculated.</strong> Normals are derived from edge vectors, and edge labels use the lattice edge lengths already computed from gcds.</p>", "Pointed / Fano data": "<p><strong>What it is.</strong> Invariants depending on a chosen interior lattice point used as origin, especially for Fano/LDP interpretations.</p><p><strong>How it is calculated.</strong> The app shifts the polygon by the selected origin \\(o\\), forming \\(Q=P-o\\), then computes facet distances, polar vertices, cone orders, and singularity content.</p>", "Pointed diagnostic data": "<p><strong>What it is.</strong> Pointed data shown when the shifted vertices are not all primitive, so the strict Fano/LDP interpretation does not apply.</p><p><strong>How it is calculated.</strong> The same shifted-polygon formulas are used, but rows are labelled diagnostic because nonprimitive rays violate the usual Fano polygon convention.</p>", "Selected origin": "<p><strong>What it is.</strong> The interior lattice point currently chosen as the origin for pointed/Fano computations.</p><p><strong>How it is used.</strong> The app shifts all vertices by \\(Q=P-o\\). Facet distances, polar duals, reflexivity, and singularity content depend on this choice.</p>", "Facet distances / edge widths": "<p><strong>What it is.</strong> The local distances from the selected origin to each supporting facet and the lattice lengths of the corresponding edges.</p><p><strong>How it is calculated.</strong> For \\(Q=P-o\\), write \\(Q=\\{x:\\langle n_i,x\\rangle\\le h_i\\}\\). The \\(h_i\\) are facet distances; edge widths are gcd lattice lengths of shifted edges.</p>", "Pointed / Gorenstein index": "<p><strong>What it is.</strong> The least common multiple of all facet distances from the selected origin.</p><p><strong>How it is calculated.</strong> The app computes \\(\\operatorname{lcm}(h_1,\\ldots,h_r)\\). Index 1 with primitive shifted vertices is the reflexive/Gorenstein case.</p>", "Reflexive for this origin": "<p><strong>What it is.</strong> Whether the selected origin makes the polygon reflexive in the two-dimensional toric sense.</p><p><strong>How it is calculated.</strong> The app checks whether all facet distances \\(h_i=1\\). This is meaningful when the selected point is interior and shifted vertices are primitive.</p>", "Primitive shifted vertices": "<p><strong>What it is.</strong> Whether every ray from the selected origin to a polygon vertex is primitive.</p><p><strong>How it is calculated.</strong> For each shifted vertex \\(q_i=v_i-o\\), the app checks \\(\\gcd(|q_{i1}|,|q_{i2}|)=1\\).</p>", "LDP polygon for this origin": "<p><strong>What it is.</strong> Whether the pointed polygon satisfies the primitive-vertex condition expected of a lattice Fano/LDP polygon.</p><p><strong>How it is calculated.</strong> The app checks primitive shifted vertices. Additional singularity rows then describe the cones over edges.</p>", "Polar vertices": "<p><strong>What it is.</strong> The rational vertices of the polar dual of the shifted polygon.</p><p><strong>How it is calculated.</strong> If \\(Q=\\{x:\\langle n_i,x\\rangle\\le h_i\\}\\), then the polar dual has vertices \\(n_i/h_i\\).</p>", "Cone orders over edges": "<p><strong>What it is.</strong> The cyclic quotient orders for cones over the edges of the shifted polygon.</p><p><strong>How it is calculated.</strong> For adjacent shifted vertices \\(q_i,q_{i+1}\\), the order is \\(|\\det(q_i,q_{i+1})|\\).</p>", "Primitive T-cone count": "<p><strong>What it is.</strong> The total number of primitive T-cone blocks in the singularity-content decomposition.</p><p><strong>How it is calculated.</strong> For each edge, write edge width \\(\\ell_i=n_i h_i+\\rho_i\\). The app sums the quotients \\(n_i\\).</p>", "T-singularity quotient data (n,ρ)": "<p><strong>What it is.</strong> The quotient and remainder data for decomposing each edge into T-cone blocks plus residual cone.</p><p><strong>How it is calculated.</strong> The app computes \\(\\ell_i=n_i h_i+\\rho_i\\) for every edge and displays \\((n_i,\\rho_i)\\).</p>", "Singularity content / residual basket": "<p><strong>What it is.</strong> The residual singularities remaining after removing T-cone blocks from all edges.</p><p><strong>How it is calculated.</strong> For each edge with \\(\\rho_i>0\\), the app reconstructs the residual subcone and computes its cyclic quotient type \\(1/r(1,a)\\) and HJ chain.</p>", "Diagnostic residual basket": "<p><strong>What it is.</strong> A residual-basket calculation displayed in diagnostic mode when the shifted polygon is not a strict Fano polygon.</p><p><strong>How it is calculated.</strong> The same edge decomposition \\(\\ell=n h+\\rho\\) and quotient-cone calculations are used, but the app avoids claiming a strict singularity-content classification.</p>", "Residual HJ graph": "<p><strong>What it is.</strong> The Hirzebruch-Jung continued-fraction chain for each residual cyclic quotient cone.</p><p><strong>How it is calculated.</strong> For quotient type \\(1/r(1,a)\\), the app computes the negative continued fraction expansion of \\(r/a\\).</p>", "Residual mld / min discrepancy proxy": "<p><strong>What it is.</strong> Minimal log discrepancy and minimal discrepancy diagnostics for the residual basket.</p><p><strong>How it is calculated.</strong> The app resolves residual cones torically, computes discrepancies for resolution rays, and takes the minimum displayed values.</p>", "Residual canonical / terminal / log terminal proxy": "<p><strong>What it is.</strong> Singularity status diagnostics inferred from residual-cone discrepancies.</p><p><strong>How it is calculated.</strong> Canonical/terminal/log-terminal flags are read from signs of the computed discrepancy and log-discrepancy values for toric resolution rays.</p>", "Mutation-class fingerprint": "<p><strong>What it is.</strong> A compact string intended to compare pointed polygons by mutation-relevant diagnostics.</p><p><strong>How it is calculated.</strong> It combines total T-count, pointed index, residual basket quotient types, and primitive dual statistics. It is a fingerprint, not a complete invariant.</p>", "Dual polygon search": "<p><strong>What it is.</strong> The polar dual of the selected pointed polygon, scaled and primitive-reduced so it can be searched as a lattice polygon.</p><p><strong>How it is calculated.</strong> For \\(Q=P-o\\) with inequalities \\(\\langle n_i,x\\rangle\\le h_i\\), the rational dual has vertices \\(n_i/h_i\\). The app multiplies by the least common multiple of the \\(h_i\\), takes the convex hull, divides by primitive content, then searches for AGL2(Z)-equivalent records.</p>", "Displayed object": "<p><strong>What it is.</strong> The exact kind of dual polygon currently shown: integral, least-integral scaled, primitive-reduced, or scaled by the pointed index.</p><p><strong>How it is calculated.</strong> The app reports whether the rational polar was already integral, what scale was needed, and whether a further common lattice-content division was applied.</p>", "Facet distances of shifted polygon": "<p><strong>What it is.</strong> The support numbers \\(h_i\\) of \\(Q=P-o\\) with respect to primitive outward normals.</p><p><strong>How it is calculated.</strong> \\(h_i=\\max_{q\\in Q}\\langle n_i,q\\rangle\\). These distances determine the denominators of the polar dual vertices \\(n_i/h_i\\).</p>", "Integral scale before primitive reduction": "<p><strong>What it is.</strong> The least scale used to make the rational polar dual integral.</p><p><strong>How it is calculated.</strong> The app uses \\(\\operatorname{lcm}(h_i)\\) as the clearing denominator; when all dual vertices are already integral, this scale is 1.</p>", "Primitive reduction factor": "<p><strong>What it is.</strong> The common lattice dilation factor removed after the integral dual is formed.</p><p><strong>How it is calculated.</strong> After choosing an anchor vertex of the integral dual, the app takes the gcd of all coordinate differences and divides by it if greater than 1.</p>", "Primitive dual display grid": "<p><strong>What it is.</strong> The width and height of the grid needed to draw the primitive dual polygon.</p><p><strong>How it is calculated.</strong> The app takes the bounding box of the primitive dual vertices. Very large grids trigger a guard that skips point-grid drawing and copying.</p>", "Primitive dual stats": "<p><strong>What it is.</strong> The basic lattice statistics of the primitive dual polygon.</p><p><strong>How it is calculated.</strong> After scaling and primitive reduction, the app recomputes \\(\\operatorname{Vol},B,I,N\\) by the same polygon formulas used for ordinary records.</p>", "Normalized Mahler proxy": "<p><strong>What it is.</strong> A lattice analogue of the volume product for the polygon and its displayed primitive dual.</p><p><strong>How it is calculated.</strong> The app multiplies normalized volumes: \\(\\operatorname{Vol}(P)\\operatorname{Vol}(P^\\vee_{prim})\\). Because of scaling/primitive reduction, it is labelled a proxy.</p>", "Barycenter / Futaki proxy": "<p><strong>What it is.</strong> A centroid diagnostic related to toric Futaki/K-stability heuristics.</p><p><strong>How it is calculated.</strong> The app displays area centroids of \\(P\\) and, when feasible, of the primitive dual. It does not perform a full K-stability calculation.</p>", "Primitive polygon search": "<p><strong>What it is.</strong> A derived search for the polygon obtained by removing a common lattice dilation from the current polygon.</p><p><strong>How it is calculated.</strong> If \\(P=v_0+dP'\\) with maximal \\(d>1\\), the app displays \\(P'=(P-v_0)/d\\) and searches it in the same database.</p>", "Dilation factor removed": "<p><strong>What it is.</strong> The maximal integer \\(d\\) divided out to obtain the primitive polygon.</p><p><strong>How it is calculated.</strong> It is the gcd of all coordinate differences from the anchor vertex.</p>", "Anchor vertex before division": "<p><strong>What it is.</strong> The vertex used as the translation anchor before dividing by the dilation factor.</p><p><strong>How it is calculated.</strong> The app chooses an anchor from the hull vertex list, subtracts it from all vertices, divides by the gcd content, then canonicalizes the result.</p>", "Primitive polygon stats": "<p><strong>What it is.</strong> The basic invariants of the primitive polygon after content removal.</p><p><strong>How it is calculated.</strong> The app recomputes \\(\\operatorname{Vol},B,I,N\\) from the primitive vertex list.</p>", "Single-lattice-point neighbours": "<p><strong>What it is.</strong> Polygons obtained by adding or removing exactly one lattice point from the full lattice-point set, when the result is still the full lattice-point set of its convex hull.</p><p><strong>How it is calculated.</strong> The app tests deletion of existing lattice points and addition of nearby lattice points within the chosen radius, then verifies convex hull equality and searches database matches.</p>", "Add-point search radius": "<p><strong>What it is.</strong> The radius controlling how far outside the current polygon the neighbour search tries adding one lattice point.</p><p><strong>How it is calculated.</strong> The app scans candidate lattice points in a bounding box enlarged by this radius, then keeps only additions whose convex hull has the expected full lattice-point set.</p>", "Selected DAG node information": "<p><strong>What it is.</strong> Information for the currently selected node in the toric blow-down directed acyclic graph.</p><p><strong>How it is calculated.</strong> Nodes encode fans/divisors reached by sequences of toric contractions. Parent/child edges record contractible curves and multiplicities.</p>", "Selected node": "<p><strong>What it is.</strong> The index of the active node in the blow-down DAG display.</p><p><strong>How it is calculated.</strong> The app assigns node numbers as it enumerates reachable toric contraction states.</p>", "Root node": "<p><strong>What it is.</strong> Whether the selected DAG node is the starting fan before any listed contraction.</p><p><strong>How it is calculated.</strong> The root is node #0, with an empty contraction path.</p>", "Terminal / minimal endpoint": "<p><strong>What it is.</strong> Whether no further toric (-1)-curve contraction is available from this node.</p><p><strong>How it is calculated.</strong> The app computes self-intersections of invariant curves and checks for contractible (-1)-curves in the current fan.</p>", "Depth / paths to node": "<p><strong>What it is.</strong> The length of a representative contraction path and the number of paths found to the node.</p><p><strong>How it is calculated.</strong> During DAG enumeration, depth counts contractions from the root and path count accumulates equivalent ways to reach the same fan state.</p>", "Parent nodes": "<p><strong>What it is.</strong> Nodes that contract to the selected node in one step.</p><p><strong>How it is calculated.</strong> The app records directed edges when a fan state is obtained by contracting a listed invariant curve.</p>", "Child nodes": "<p><strong>What it is.</strong> Nodes reachable by one further contraction from the selected node.</p><p><strong>How it is calculated.</strong> The app finds contractible (-1)-curves in the selected fan and creates child states from their contractions.</p>", "Representative contraction path": "<p><strong>What it is.</strong> One displayed sequence of contractions leading from the root to the selected node.</p><p><strong>How it is calculated.</strong> The app stores one path during DAG traversal; other paths may also exist and are counted separately.</p>", "Fan rays": "<p><strong>What it is.</strong> The primitive rays of the current fan node.</p><p><strong>How it is calculated.</strong> Rays are updated by star subdivisions for blow-ups and by removing contractible rays for blow-downs.</p>", "Support constants": "<p><strong>What it is.</strong> The support numbers of the current divisor/polytope with respect to fan rays.</p><p><strong>How it is calculated.</strong> For each ray \\(\\nu_i\\), the support constant is \\(h_i=\\max_{p\\in P}\\langle\\nu_i,p\\rangle\\), updated under selected birational operations.</p>", "Picard rank / invariant curves": "<p><strong>What it is.</strong> The rank proxy and number of torus-invariant curves at the current fan node.</p><p><strong>How it is calculated.</strong> For a complete toric surface fan with \\(r\\) rays, the rank is \\(r-2\\), and invariant curves correspond to the \\(r\\) rays.</p>", "Self-intersection sequence": "<p><strong>What it is.</strong> The cyclic sequence of self-intersections of invariant divisors/curves in the current fan.</p><p><strong>How it is calculated.</strong> The app evaluates toric self-intersection formulas from adjacent rays and displays the sequence.</p>", "Next contractible (-1)-curves": "<p><strong>What it is.</strong> Invariant curves currently eligible for toric contraction.</p><p><strong>How it is calculated.</strong> In smooth fan states, invariant curves with self-intersection -1 are listed as possible next contractions.</p>", "Endpoint type": "<p><strong>What it is.</strong> The minimal-model type assigned to a terminal DAG node.</p><p><strong>How it is calculated.</strong> The app classifies terminal smooth toric fans using fan self-intersections and ruled/plane-type signals.</p>", "K^2": "<p><strong>What it is.</strong> The canonical self-intersection at the current DAG node.</p><p><strong>How it is calculated.</strong> The app evaluates \\(K^2=(-K)^2\\) from the current fan's rational intersection matrix.</p>", "L^2 / (-K).L proxy": "<p><strong>What it is.</strong> The current polarizing class self-intersection and anticanonical pairing proxy after contractions/modifications.</p><p><strong>How it is calculated.</strong> The app updates divisor support constants and computes intersection numbers using the current fan matrix.</p>", "Anti-canonical degrees": "<p><strong>What it is.</strong> The values \\((-K)\\cdot D_i\\) on invariant curves of the current fan.</p><p><strong>How it is calculated.</strong> They are computed from the current toric intersection matrix and the divisor \\(-K=\\sum_iD_i\\).</p>", "Minimal model class sample": "<p><strong>What it is.</strong> A sample divisor-class description for the terminal toric minimal model.</p><p><strong>How it is calculated.</strong> The app reads the terminal fan type and expresses sample classes using the current rational divisor basis.</p>", "Search": "<p><strong>What it is.</strong> A command to run the selected filters against the metadata and, where needed, exact vertex data.</p><p><strong>How it works.</strong> Empty fields are ignored, but the completely empty Reset state is not searched. Matching rows are capped by Display limit and then grouped by exact AGL2(Z) equivalence where possible.</p>", "max order": "<p><strong>What it is.</strong> The truncation order used for a displayed power series or period computation.</p><p><strong>How it is used.</strong> Larger values request more coefficients and may take longer because exact integer/rational computations are performed in the browser.</p>", "Mirror period support": "<p><strong>What it is.</strong> Which monomials are used to build the Laurent polynomial for constant-term period calculations.</p><p><strong>How it is calculated.</strong> The app can use all lattice points, vertices only, or boundary points, then computes constant terms \\(\\operatorname{CT}(f^k)\\) after the selected origin translation.</p>", "max decompositions": "<p><strong>What it is.</strong> The maximum number of Minkowski decompositions to list.</p><p><strong>How it is used.</strong> The search stops after this many verified decompositions to keep the browser responsive.</p>", "Blow-up type": "<p><strong>What it is.</strong> The toric birational operation applied in the blow-up laboratory.</p><p><strong>How it is calculated.</strong> Ordinary and weighted options insert rays into cones; resolution options insert chains until singular cones become smooth.</p>", "corner-cut / multiplicity k": "<p><strong>What it is.</strong> The size parameter for corner cuts or repeated toric modifications.</p><p><strong>How it is used.</strong> It changes the support constants/ray insertion data before the app recomputes the modified fan and clipped polygon.</p>", "number of rounds / points": "<p><strong>What it is.</strong> The number of iterative blow-up rounds or point-count parameter used by the selected blow-up mode.</p><p><strong>How it is used.</strong> The app repeats the chosen ray-insertion pattern up to this bound.</p>", "weight a": "<p><strong>What it is.</strong> The first weight in a weighted toric star subdivision.</p><p><strong>How it is used.</strong> Together with weight b it determines the inserted ray between the adjacent cone rays.</p>", "weight b": "<p><strong>What it is.</strong> The second weight in a weighted toric star subdivision.</p><p><strong>How it is used.</strong> Together with weight a it determines the inserted ray between the adjacent cone rays.</p>"};
const HELP_ALIASES={"Vol": "Normalized volume", "V": "Number of vertices", "B": "Boundary points", "I": "Interior points", "N": "Total lattice points", "lw": "Lattice width", "edge": "Edge length cycle", "vertices": "Number of vertices", "level": "Adjoint depth", "polygon search": "Search", "Record": "Record ID", "LP": "Record ID", "merged": "Results", "small-polytopes": "Source", "LDP": "Source", "both": "Source", "drawn": "Source", "max order": "max order", "Mirror period support": "Mirror period support", "max decompositions": "max decompositions", "Blow-up type": "Blow-up type", "corner-cut / multiplicity k": "corner-cut / multiplicity k", "number of rounds / points": "number of rounds / points", "weight a": "weight a", "weight b": "weight b"};
Object.assign(HELP_TEXT,{"Centroids": "<p><strong>What it is.</strong> A visual and numeric comparison of several centers of the polygon: area centroid, all-lattice-point centroid, boundary centroid, and interior centroid when defined.</p><p><strong>How it is calculated.</strong> The area centroid uses the shoelace centroid formula; lattice centroids are arithmetic averages over the corresponding enumerated lattice-point sets.</p>", "About this build": "<p><strong>What it is.</strong> Notes about the implementation strategy of the current database build.</p><p><strong>How it works.</strong> Search uses a fast metadata layer and lazy-loads full vertices only when exact geometry, details, or derived searches are needed.</p>", "Definitions and formulas": "<p><strong>What it is.</strong> The formula reference for the immediately preceding section.</p><p><strong>How it is calculated.</strong> It records the exact definitions used by the browser code, typically determinant, gcd, Pick/Ehrhart, or toric intersection formulas.</p>", "Generating functions for #(kP∩M) and #((kP)^circ∩M)": "<p><strong>What it is.</strong> The explicit initial terms of the Ehrhart and interior Ehrhart generating functions.</p><p><strong>How it is calculated.</strong> The app evaluates \\(L_P(k)=(\\operatorname{Vol}k^2+Bk+2)/2\\) and its reciprocity interior analogue up to the selected order.</p>", "Mathematical background": "<p><strong>What it is.</strong> A short theoretical explanation for the displayed computational formulas.</p><p><strong>How it is used.</strong> It clarifies which lattice-polygon theorem or toric dictionary justifies the row values above.</p>", "Invariant divisors in a rational class-group basis": "<p><strong>What it is.</strong> A table expressing invariant divisors in the chosen rational class-group basis.</p><p><strong>How it is calculated.</strong> The app quotients the free divisor group by principal divisor relations from the fan ray matrix, then displays coordinates in a rational splitting.</p>", "Cox grading and irrelevant ideal data": "<p><strong>What it is.</strong> Cox homogeneous coordinate data for the fan.</p><p><strong>How it is calculated.</strong> One variable is assigned to each ray; the grading comes from the class group, and the irrelevant ideal comes from complements of maximal cones.</p>", "Mori wall relations and anti-canonical degrees": "<p><strong>What it is.</strong> Toric curve relations and anticanonical intersections on invariant curves.</p><p><strong>How it is calculated.</strong> The app computes wall relations among adjacent fan rays and evaluates \\((-K_X)\\cdot D_i\\) using the intersection matrix.</p>", "Complete invariant-divisor intersection matrix": "<p><strong>What it is.</strong> The full rational intersection matrix of torus-invariant divisors.</p><p><strong>How it is calculated.</strong> Adjacent divisor intersections are reciprocal cone multiplicities, non-adjacent intersections are zero, and self-intersections use the standard determinant formula.</p>", "Toric blow-up / birational modification laboratory": "<p><strong>What it is.</strong> An interactive module for toric star subdivisions, resolutions, and related polygon clipping.</p><p><strong>How it is calculated.</strong> Selected cones receive inserted rays according to the chosen mode; the app recomputes fan rays, support constants, divisor intersections, singularities, and clipped polygons.</p>", "Exceptional divisors, discrepancies and self-intersections": "<p><strong>What it is.</strong> Data for rays introduced by toric blow-ups or resolutions.</p><p><strong>How it is calculated.</strong> Each inserted ray defines an exceptional divisor; discrepancies and self-intersections are computed from adjacent rays in the modified fan.</p>", "Singular cone table after modification": "<p><strong>What it is.</strong> A table of remaining singular cones after the selected birational operation.</p><p><strong>How it is calculated.</strong> The app recomputes all adjacent determinants \\(|\\det(\\nu_i,\\nu_{i+1})|\\) and lists cones with multiplicity greater than 1.</p>", "Intersection matrix after modification": "<p><strong>What it is.</strong> The invariant-divisor intersection matrix for the modified fan.</p><p><strong>How it is calculated.</strong> The same toric intersection formulas are applied to the new cyclic ray sequence after inserted or contracted rays are included.</p>", "Birational toric minimal-model data": "<p><strong>What it is.</strong> Smooth-fan contraction diagnostics related to the toric minimal model program.</p><p><strong>How it is calculated.</strong> The app lists self-intersections, detects invariant (-1)-curves, and explores contractions when the normal fan is smooth.</p>", "Blow-up result birational toric minimal-model data": "<p><strong>What it is.</strong> Minimal-model diagnostics after a selected blow-up or fan modification.</p><p><strong>How it is calculated.</strong> The app recomputes smoothness, self-intersections, and contractible invariant curves for the modified fan state.</p>", "Node table": "<p><strong>What it is.</strong> The list of nodes in a computed blow-down DAG.</p><p><strong>How it is calculated.</strong> Each node represents a fan state; directed edges are created by contracting eligible toric (-1)-curves.</p>", "Endpoint paths and base-point multiplicity record": "<p><strong>What it is.</strong> A record of contraction paths ending at terminal/minimal nodes.</p><p><strong>How it is calculated.</strong> The DAG traversal stores representative paths and multiplicity data along contractions.</p>", "Adjoint tower and subcurve polygons": "<p><strong>What it is.</strong> The successive interior polygons obtained by adjunction.</p><p><strong>How it is calculated.</strong> Starting with \\(P\\), the app repeatedly takes the convex hull of strict interior lattice points, recording \\(\\operatorname{Vol},B,I,N\\) at each level and searching database matches.</p>", "Curve-counting and mirror-symmetry computations": "<p><strong>What it is.</strong> Optional exact calculations for constant-term periods, Picard-Fuchs guessing, and mirror-map diagnostics.</p><p><strong>How it is calculated.</strong> The app builds a Laurent polynomial from the selected support, computes \\(\\operatorname{CT}(f^k)\\), then uses exact linear algebra to guess and verify differential operators.</p>", "Classical period coefficients used": "<p><strong>What it is.</strong> The period series coefficients passed to the Picard-Fuchs search.</p><p><strong>How it is calculated.</strong> Coefficients are exact constant terms \\(\\operatorname{CT}(f^k)\\), sometimes reduced by stride when early coefficients vanish periodically.</p>", "Riemann-symbol data at 0 and infinity": "<p><strong>What it is.</strong> Local exponent diagnostics of the guessed Picard-Fuchs operator.</p><p><strong>How it is calculated.</strong> The app forms indicial equations at \\(z=0\\) and \\(z=\\infty\\) from the differential operator in \\(\\theta=z\\frac{d}{dz}\\).</p>", "Mirror map": "<p><strong>What it is.</strong> The formal coordinate change \\(q(z)\\) and its inverse \\(z(q)\\) derived from period/log-solution data.</p><p><strong>How it is calculated.</strong> The app computes a logarithmic companion solution, forms \\(q=z\\exp(g/f)\\), then inverts the power series exactly to the requested order.</p>", "Mirror-map Lambert diagnostic coefficients": "<p><strong>What it is.</strong> Coefficients extracted from a Lambert-series style expansion of the inverse mirror map.</p><p><strong>How it is calculated.</strong> The app manipulates formal power series and Möbius/Lambert-type recursions; the output is labelled diagnostic rather than enumerative invariants.</p>", "Singularity content, residual cones and discrepancies": "<p><strong>What it is.</strong> The detailed table behind the pointed singularity-content summary.</p><p><strong>How it is calculated.</strong> For each edge the app decomposes \\(\\ell=n h+\\rho\\), reconstructs residual cones, computes quotient types, HJ chains, and toric discrepancy values.</p>", "Nonzero coefficient rows": "<p><strong>What it is.</strong> A sparse display of nonzero coefficients in an operator or series computation.</p><p><strong>How it is calculated.</strong> Zero coefficients are suppressed after exact arithmetic, leaving only terms that affect the displayed expression.</p>"});
Object.assign(HELP_TEXT,{
  "K_X Cartier index": "<p><strong>What it is.</strong> The Cartier index of the canonical divisor of the toric surface defined by the normal fan. It is the smallest positive integer \\(r\\) for which \\(rK_X\\) is Cartier.</p><p><strong>How it is calculated.</strong> For each two-dimensional cone \\(\\sigma=\\langle u_i,u_{i+1}\\rangle\\), the app solves the local Cartier equation \\(m_\\sigma(u_i)=m_\\sigma(u_{i+1})=1\\). The local denominator gives a local Gorenstein index, and the global index is their least common multiple.</p>",
  "Gorenstein fan (K_X Cartier)": "<p><strong>What it is.</strong> Whether the normal fan is Gorenstein, equivalently whether \\(K_X\\) is Cartier for the associated toric surface.</p><p><strong>How it is calculated.</strong> The app computes the \\(K_X\\) Cartier index. The answer is yes exactly when that index equals \\(1\\).</p>",
  "Class-group torsion order": "<p><strong>What it is.</strong> The order of the torsion subgroup of the divisor class group \\(\\operatorname{Cl}(X)\\) of the toric surface.</p><p><strong>How it is calculated.</strong> For the fan rays in \\(N\\), the torsion order is the gcd of all two-by-two determinants \\( |\\det(u_i,u_j)| \\). A value of \\(1\\) means the class group is torsion-free.</p>",
  "(-K_X)^2": "<p><strong>What it is.</strong> The rational self-intersection number of the anticanonical divisor on the possibly singular toric surface determined by the normal fan.</p><p><strong>How it is calculated.</strong> The app forms the toric intersection matrix: adjacent divisors have intersection \\(1/|\\det(u_i,u_{i+1})|\\), non-adjacent divisors have intersection \\(0\\), and self-intersections use the standard determinant formula. It then sums the entries for \\(-K_X=\\sum_i D_i\\).</p>",
  "Fano index (free part)": "<p><strong>What it is.</strong> The divisibility of the anticanonical class in the free part of \\(\\operatorname{Cl}(X)\\). It is a toric analogue of the Fano index, with torsion recorded separately.</p><p><strong>How it is calculated.</strong> The app expresses \\(-K_X=\\sum_iD_i\\) in a rational/free class-group basis and takes the gcd of the integral coordinates in the free part.</p>",
  "Number of smooth cones": "<p><strong>What it is.</strong> The number of two-dimensional cones of the normal fan that are smooth/unimodular.</p><p><strong>How it is calculated.</strong> For consecutive primitive rays \\(u_i,u_{i+1}\\), the cone is smooth exactly when \\(|\\det(u_i,u_{i+1})|=1\\). The app counts such cones.</p>",
  "Projective dimension": "<p><strong>What it is.</strong> The dimension of the projective space determined by all lattice monomials of the polygon.</p><p><strong>How it is calculated.</strong> If \\(N=\\#(P\\cap M)\\), then the complete linear system embeds or maps the toric surface into \\(\\mathbb P^{N-1}\\). The displayed value is \\(N-1\\).</p>",
  "Projective codimension": "<p><strong>What it is.</strong> The codimension of the toric surface inside the ambient projective space associated with all lattice points of \\(P\\).</p><p><strong>How it is calculated.</strong> A toric surface has dimension \\(2\\), and the ambient projective space has dimension \\(N-1\\). Thus the codimension is \\((N-1)-2=N-3\\).</p>",
  "Sectional genus": "<p><strong>What it is.</strong> The arithmetic genus of a general curve in the linear system associated with \\(P\\).</p><p><strong>How it is calculated.</strong> For a lattice polygon, the sectional genus equals the number of strict interior lattice points: \\(g=\\#(P^\\circ\\cap M)=I\\).</p>",
  "Canonical linear-system dimension": "<p><strong>What it is.</strong> The projective dimension of the adjoint/canonical linear system cut out by the strict interior lattice points of \\(P\\).</p><p><strong>How it is calculated.</strong> If \\(I>0\\), the dimension is \\(I-1\\). If there are no interior lattice points, the canonical system is empty and this filter treats the value as \\(-1\\).</p>",
  "Adjoint-tower depth": "<p><strong>What it is.</strong> The number of nonempty polygonal stages in the adjoint tower obtained by repeatedly replacing a polygon by the convex hull of its strict interior lattice points.</p><p><strong>How it is calculated.</strong> Starting from \\(P_0=P\\), the app forms \\(P_{j+1}=\\operatorname{conv}(P_j^\\circ\\cap M)\\) while this is two-dimensional. The depth is the largest level reached before the process stops.</p>",
  "Canonical polygon vertices": "<p><strong>What it is.</strong> The number of vertices of the canonical or adjoint polygon \\(\\operatorname{conv}(P^\\circ\\cap M)\\).</p><p><strong>How it is calculated.</strong> The app enumerates strict interior lattice points, takes their convex hull, removes collinear non-corner points, and counts the remaining vertices. If the adjoint polygon is empty or lower-dimensional, the value is \\(0\\).</p>",
  "Affine automorphism group order": "<p><strong>What it is.</strong> The order of the affine unimodular symmetry group preserving the polygon.</p><p><strong>How it is calculated.</strong> The app searches transformations \\(x\\mapsto Ax+t\\), with \\(A\\in\\operatorname{GL}_2(\\mathbb Z)\\) and \\(t\\in\\mathbb Z^2\\), that send the vertex set of \\(P\\) to itself. The order is the number of verified maps.</p>",
  "Orientation-preserving automorphisms": "<p><strong>What it is.</strong> The number of polygon automorphisms whose linear part has determinant \\(+1\\).</p><p><strong>How it is calculated.</strong> After enumerating all affine unimodular automorphisms \\(x\\mapsto Ax+t\\), the app counts those with \\(\\det A=1\\).</p>",
  "Orientation-reversing automorphisms": "<p><strong>What it is.</strong> The number of polygon automorphisms whose linear part has determinant \\(-1\\), such as reflection-type symmetries.</p><p><strong>How it is calculated.</strong> After enumerating all affine unimodular automorphisms \\(x\\mapsto Ax+t\\), the app counts those with \\(\\det A=-1\\).</p>",
  "Has nontrivial symmetry": "<p><strong>What it is.</strong> Whether the polygon has any affine unimodular symmetry other than the identity.</p><p><strong>How it is calculated.</strong> The app computes the affine automorphism group and checks whether its order is greater than \\(1\\).</p>",
  "Has reflection / orientation reversal": "<p><strong>What it is.</strong> Whether the symmetry group contains an orientation-reversing affine unimodular map.</p><p><strong>How it is calculated.</strong> The app computes all affine automorphisms and checks whether at least one has linear determinant \\(-1\\).</p>",
  "Symmetry group type": "<p><strong>What it is.</strong> A coarse classification of the affine unimodular symmetry group: trivial, order-two \\(C_2\\), orientation-preserving cyclic type, or dihedral-type with orientation-reversing elements.</p><p><strong>How it is calculated.</strong> The app uses the computed automorphism order and the counts with determinants \\(+1\\) and \\(-1\\). This is a practical database label rather than a full abstract group presentation.</p>"
});

Object.assign(HELP_ALIASES,{"Reachable \\\\mathbb P^2\\":"Reachable \\(\\mathbb P^2\\)","Reachable \\\\mathbb F_0\\":"Reachable \\(\\mathbb F_0\\)","K^2, L^2, (-K).L proxy":"K^2, L^2, (-K).L proxy","\\(-K)^2\\ after blow-up":"((-K)^2) after blow-up","(-K)^2 after blow-up":"((-K)^2) after blow-up","\\(-K)^2\\ after modification":"((-K)^2) after modification","(-K)^2 after modification":"((-K)^2) after modification","\\pi^*L-k\\sum E_i)^2":"((\\pi^*L-k\\sum E_i)^2)","(\\pi^*L-k\\sum E_i)^2":"((\\pi^*L-k\\sum E_i)^2)","K_{\\tilde X}·(\\pi^*L-k\\sum E_i)":"K_{\\tilde X}\\cdot(\\pi^*L-k\\sum E_i)","K_X Cartier index after modification":"K_X Cartier index after modification","Segment vector u":"Segment vector \\(u\\)","Segment vector \\u\\":"Segment vector \\(u\\)","Generating functions for #(kP\\cap M) and #((kP)^\\circ\\cap M)":"Generating functions for #(kP∩M) and #((kP)^circ∩M)","Generating functions for #(kP∩M) and #((kP)^∘∩M)":"Generating functions for #(kP∩M) and #((kP)^circ∩M)","h^*-vector and symmetry":"h^*-vector and symmetry","h^* unimodality / log-concavity":"h^* unimodality / log-concavity"});
Object.assign(HELP_TEXT,{"id":"<p><strong>What it is.</strong> The short table key for the stored record identifier.</p><p><strong>How it is assigned.</strong> It is read from the database metadata and displayed as an LP-number in the interface; it is not a polygon invariant.</p>","box":"<p><strong>What it is.</strong> The metadata/search key for the minimum displayed square size.</p><p><strong>How it is calculated.</strong> The app minimizes the larger coordinate span over affine unimodular coordinate systems, so the value is stable under AGL₂(ℤ) equivalence.</p>","Type":"<p><strong>What it is.</strong> The qualitative category assigned to a row in the current table, such as a cone type, endpoint type, blow-up mode, or symmetry type.</p><p><strong>How it is assigned.</strong> The type is selected from the local calculation feeding that table: fan determinants for cones, self-intersection data for minimal endpoints, or affine automorphism data for symmetry rows.</p>","Mode":"<p><strong>What it is.</strong> The selected computational mode or birational operation used by the current module.</p><p><strong>How it is used.</strong> The mode controls which exact algorithm is run, for example which toric star subdivision, resolution step, or polygon clipping rule is applied before invariants are recomputed.</p>","Could not render record":"<p><strong>What it is.</strong> An error card shown when the selected record cannot be opened or one of its derived computations fails.</p><p><strong>How it is produced.</strong> The app catches the rendering exception, prints the error message and stack trace, and leaves the rest of the search results usable.</p>","max DAG nodes":"<p><strong>What it is.</strong> The node cap for the toric blow-down directed acyclic graph.</p><p><strong>How it is used.</strong> The app enumerates smooth toric contractions of invariant (-1)-curves until either all reachable nodes are listed or this cap is reached, preventing very large DAGs from freezing the browser.</p>","Nodes / edges":"<p><strong>What it is.</strong> The size of the computed blow-down DAG.</p><p><strong>How it is calculated.</strong> A node is a fan state; a directed edge is one valid contraction of a torus-invariant (-1)-curve from one smooth fan state to another.</p>","Minimal endpoint states":"<p><strong>What it is.</strong> The terminal nodes of the blow-down DAG where no further toric (-1)-curve contraction is available.</p><p><strong>How it is calculated.</strong> After each contraction the app recomputes self-intersections. Nodes with no divisor of self-intersection -1 are counted as minimal endpoints.</p>","Blow-down path count":"<p><strong>What it is.</strong> The number of contraction sequences recorded in the computed DAG.</p><p><strong>How it is calculated.</strong> Path counts are accumulated along directed edges from the root fan, so different orders of contracting disjoint or later-available (-1)-curves are counted separately.</p>","Minimal model unique by endpoint type":"<p><strong>What it is.</strong> A coarse uniqueness check for the endpoint types reached by the toric MMP search.</p><p><strong>How it is calculated.</strong> The app compares the labels of terminal fan types such as \\(\\mathbb P^2\\) and Hirzebruch surfaces \\(\\mathbb F_a\\). It is a toric endpoint diagnostic, not a statement about non-toric birational uniqueness.</p>","Path length range":"<p><strong>What it is.</strong> The minimum and maximum number of contractions among recorded paths to terminal endpoints.</p><p><strong>How it is calculated.</strong> Each directed edge contributes one contraction; the app reads the depths of terminal nodes and reports the smallest and largest depths.</p>","Reachable \\(\\mathbb P^2\\)":"<p><strong>What it is.</strong> Whether the computed toric blow-down DAG has an endpoint whose fan is the fan of the projective plane.</p><p><strong>How it is calculated.</strong> A terminal smooth fan with three rays is classified as \\(\\mathbb P^2\\) when its cyclic self-intersection pattern matches the standard toric plane.</p>","Reachable \\(\\mathbb F_0\\)":"<p><strong>What it is.</strong> Whether the computed toric blow-down DAG reaches the product Hirzebruch surface \\(\\mathbb F_0\\cong\\mathbb P^1\times\\mathbb P^1\\).</p><p><strong>How it is calculated.</strong> A terminal smooth four-ray fan is classified by its self-intersection sequence; the all-zero ruled fan is recorded as \\(\\mathbb F_0\\).</p>","Endpoint class samples":"<p><strong>What it is.</strong> Sample expressions for the polarizing class after contraction to terminal toric endpoints.</p><p><strong>How it is calculated.</strong> The app transports support-constant data along one representative contraction path and solves for familiar classes on \\(\\mathbb P^2\\) or \\(\\mathbb F_a\\) when the endpoint type is recognized.</p>","Torically minimal":"<p><strong>What it is.</strong> Whether the current smooth fan has no torus-invariant (-1)-curves.</p><p><strong>How it is calculated.</strong> The app computes the cyclic self-intersection sequence and checks whether any invariant divisor has self-intersection \\(-1\\).</p>","Toric (-1)-curves":"<p><strong>What it is.</strong> The invariant divisors that can be contracted by one smooth toric blow-down.</p><p><strong>How it is calculated.</strong> For a smooth complete fan, the app lists rays whose divisor self-intersection equals \\(-1\\); removing such a ray and joining its neighboring rays gives the contracted fan.</p>","Contractible ray count":"<p><strong>What it is.</strong> The number of toric rays/divisors currently eligible for a one-step smooth contraction.</p><p><strong>How it is calculated.</strong> It is the length of the list of invariant divisors with self-intersection \\(-1\\).</p>","Negative / zero / positive invariant curves":"<p><strong>What it is.</strong> A sign summary of the self-intersections of torus-invariant curves.</p><p><strong>How it is calculated.</strong> The app computes every invariant divisor self-intersection from adjacent fan rays and counts how many are negative, zero, and positive.</p>","Ruled fibration signal":"<p><strong>What it is.</strong> A quick toric signal that the surface may display a ruled-surface pattern.</p><p><strong>How it is calculated.</strong> The app checks whether the smooth self-intersection sequence contains an invariant curve with self-intersection zero, as happens for fibers in toric ruled surfaces.</p>","Torically minimal after modification":"<p><strong>What it is.</strong> The toric minimality test applied to the fan after the selected blow-up, resolution, or clipping operation.</p><p><strong>How it is calculated.</strong> The modified fan rays are used to recompute self-intersections; absence of invariant (-1)-curves is reported as torically minimal.</p>","K^2, L^2, (-K).L proxy":"<p><strong>What it is.</strong> A compact triple of intersection numbers for the current modified fan and divisor support data.</p><p><strong>How it is calculated.</strong> The app uses the toric intersection matrix to compute \\((-K)^2\\), the divisor square \\(L^2\\), and the anticanonical pairing \\((-K)\\cdot L\\). In this module the values are diagnostic proxies attached to the current support constants.</p>","Divisor dictionary and intersection formulas":"<p><strong>What it is.</strong> A reference block explaining the toric divisor notation and intersection formulas used in the tables.</p><p><strong>How it is used.</strong> It records the dictionary between normal fan rays, invariant divisors, support constants, class-group coordinates, and the rational intersection pairing.</p>","Background: curves, adjunction, toric MMP and periods":"<p><strong>What it is.</strong> A background note connecting polygon data to curve theory, toric birational geometry, and period computations.</p><p><strong>How it is used.</strong> It explains which displayed quantities are exact polygon/toric invariants and which are diagnostic inputs for broader curve-counting or mirror-symmetry interpretations.</p>","Segment vector \\(u\\)":"<p><strong>What it is.</strong> The lattice vector defining a segment summand \\([0,u]\\) in a tested Minkowski decomposition.</p><p><strong>How it is calculated.</strong> Candidate primitive directions come from edge and chord directions, then integer multiples are tested by checking whether \\(P=Q+[0,u]\\) holds on the full lattice-point set.</p>","Quotient vertices":"<p><strong>What it is.</strong> The vertices of the polygonal summand left after removing a segment or another Minkowski summand.</p><p><strong>How it is calculated.</strong> The app reconstructs the candidate quotient lattice-point set and takes its convex hull, then verifies the Minkowski sum against the original polygon.</p>","Normalized areas":"<p><strong>What it is.</strong> The normalized volumes of the original polygon and its candidate summands.</p><p><strong>How it is calculated.</strong> Each area is computed by the determinant/shoelace formula \\(\\operatorname{Vol}(P)=|\\sum_i\\det(v_i,v_{i+1})|\\).</p>","Database matches for quotient summand Q":"<p><strong>What it is.</strong> Database records AGL₂(ℤ)-equivalent to the quotient summand \\(Q\\).</p><p><strong>How it is calculated.</strong> The app computes the invariant signature of \\(Q\\), searches matching metadata buckets, and then verifies affine unimodular equivalence with exact vertex data.</p>","Database matches for segment summand [0,u]":"<p><strong>What it is.</strong> Database matches for the segment summand \\([0,u]\\), when such lower-dimensional matching is meaningful in the current output.</p><p><strong>How it is calculated.</strong> The segment vector is normalized by lattice direction and length. Because the main database is polygonal, lower-dimensional segment matches may be absent or reported only as diagnostics.</p>","Database matches for summand Q":"<p><strong>What it is.</strong> Stored polygon records equivalent to the first Minkowski summand \\(Q\\).</p><p><strong>How it is calculated.</strong> Candidate records are first filtered by invariant metadata and then checked by exact AGL₂(ℤ) equivalence.</p>","Database matches for summand R":"<p><strong>What it is.</strong> Stored polygon records equivalent to the second Minkowski summand \\(R\\).</p><p><strong>How it is calculated.</strong> Candidate records are first filtered by invariant metadata and then checked by exact AGL₂(ℤ) equivalence.</p>","Definitions and tested algorithms":"<p><strong>What it is.</strong> A description of the algorithms used for the adjacent Minkowski, Cayley, and convex-geometric diagnostics.</p><p><strong>How it is used.</strong> It distinguishes exact verified decompositions from bounded searches and quick structural signals such as width-one projections.</p>","Classical constant-term period":"<p><strong>What it is.</strong> The initial classical period series of a Laurent polynomial supported on the selected lattice points.</p><p><strong>How it is calculated.</strong> For \\(f=\\sum_{m\\in S}x^m\\), the app computes \\(\\Phi(z)=\\sum_k\\operatorname{CT}(f^k)z^k\\) by exact integer dynamic programming over exponent states.</p>","Picard-Fuchs guess":"<p><strong>What it is.</strong> A guessed linear differential operator annihilating the computed period series.</p><p><strong>How it is calculated.</strong> The app sets up exact integer linear equations for an operator in \\(z\\) and \\(\theta=z\\,d/dz\\), then verifies the guessed recurrence on the available coefficients.</p>","Picard-Fuchs, mirror map and period diagnostics":"<p><strong>What it is.</strong> The combined output of constant-term period computation, Picard-Fuchs guessing, and formal mirror-map diagnostics.</p><p><strong>How it is calculated.</strong> Exact period coefficients are generated first; the differential operator, indicial data, logarithmic companion solution, and inverse mirror map are then derived by rational/integer series algebra.</p>","quotient summand Q":"<p><strong>What it is.</strong> The candidate quotient polygon \\(Q\\) in a decomposition involving a segment or another summand.</p><p><strong>How it is calculated.</strong> The app determines the candidate lattice points for \\(Q\\), takes their convex hull, and verifies that the claimed Minkowski sum reconstructs the original polygon.</p>","segment summand [0,u]":"<p><strong>What it is.</strong> The lattice segment summand from the origin to the vector \\(u\\).</p><p><strong>How it is calculated.</strong> The vector \\(u\\) is tested by translating candidate quotient points and verifying equality of the reconstructed full lattice-point set with the original polygon.</p>","summand Q":"<p><strong>What it is.</strong> The first polygonal summand in a verified or candidate Minkowski decomposition \\(P=Q+R\\).</p><p><strong>How it is calculated.</strong> Candidate summands are generated from lattice directions and convex support data, then the app checks the convex-hull equality of the Minkowski sum.</p>","summand R":"<p><strong>What it is.</strong> The second polygonal summand in a verified or candidate Minkowski decomposition \\(P=Q+R\\).</p><p><strong>How it is calculated.</strong> Candidate summands are paired with \\(Q\\) and accepted only when their Minkowski sum has the same canonical vertex set as the original polygon.</p>","Toric fan":"<p><strong>What it is.</strong> The cyclic list of primitive rays defining the current toric surface fan.</p><p><strong>How it is calculated.</strong> For the original polygon these are primitive outward normals to the polygon edges; after modifications they are updated by star subdivisions or contractions.</p>","Picard rank":"<p><strong>What it is.</strong> The rank of the divisor class group/free Néron-Severi part for the displayed complete toric surface fan.</p><p><strong>How it is calculated.</strong> For a complete two-dimensional fan with \\(r\\) rays, the free rank is \\(r-2\\); torsion is reported separately when the ray lattice is not saturated.</p>","((-K)^2) after blow-up":"<p><strong>What it is.</strong> The anticanonical self-intersection after the selected toric blow-up model.</p><p><strong>How it is calculated.</strong> The app recomputes the modified fan intersection matrix and evaluates \\((-K)^2\\) for the divisor \\(-K=\\sum_iD_i\\).</p>","Exceptional curves":"<p><strong>What it is.</strong> The new torus-invariant divisors introduced by the selected blow-up or resolution.</p><p><strong>How it is calculated.</strong> Each inserted fan ray contributes one exceptional divisor; its self-intersection is read from the adjacent rays in the modified fan.</p>","((\\pi^*L-k\\sum E_i)^2)":"<p><strong>What it is.</strong> The self-intersection of a proper-transform style divisor class after subtracting multiplicity from exceptional divisors.</p><p><strong>How it is calculated.</strong> The displayed model uses the selected multiplicity \\(k\\), the original \\(L^2\\), and the toric exceptional data to form a diagnostic intersection number for \\(\\pi^*L-k\\sum E_i\\).</p>","K_{\\tilde X}\\cdot(\\pi^*L-k\\sum E_i)":"<p><strong>What it is.</strong> The canonical pairing of the modified surface with the proper-transform style divisor class.</p><p><strong>How it is calculated.</strong> The app combines the modified canonical class \\(K_{\tilde X}\\) with the selected support/multiplicity data using the toric intersection matrix.</p>","Arithmetic genus of proper-transform class":"<p><strong>What it is.</strong> The arithmetic genus predicted for the displayed proper-transform style divisor class.</p><p><strong>How it is calculated.</strong> The app applies adjunction \\(p_a=1+(D^2+K_{\tilde X}\\cdot D)/2\\) to the diagnostic class \\(D=\\pi^*L-k\\sum E_i\\).</p>","Expected independent-condition section count":"<p><strong>What it is.</strong> A heuristic count of remaining sections after imposing multiplicity conditions at selected toric points.</p><p><strong>How it is calculated.</strong> The app starts from \\(h^0(X,L)=N\\) and subtracts the expected number of independent local conditions imposed by the selected blow-up parameters.</p>","Selected original corners":"<p><strong>What it is.</strong> The polygon corners or fan cones chosen as centers for the current toric modification.</p><p><strong>How it is calculated.</strong> The interface records the selected cone indices and applies the chosen ray-insertion rule to those cones only.</p>","Inserted exceptional rays":"<p><strong>What it is.</strong> The new primitive rays added to the fan during the selected blow-up or resolution.</p><p><strong>How it is calculated.</strong> Ordinary blow-ups insert the sum of adjacent primitive rays; weighted or resolution modes insert rays determined by the selected weights or by the smooth-resolution chain.</p>","New fan rays":"<p><strong>What it is.</strong> The complete cyclic ray list after the birational fan modification.</p><p><strong>How it is calculated.</strong> The app splices inserted rays into the original fan and then normalizes/order-checks the cyclic fan data.</p>","Cone multiplicities after modification":"<p><strong>What it is.</strong> The determinant multiplicities of the two-dimensional cones in the modified fan.</p><p><strong>How it is calculated.</strong> For adjacent rays \\(\nu_i,\nu_{i+1}\\), the multiplicity is \\(|\\det(\nu_i,\nu_{i+1})|\\); value 1 means a smooth cone.</p>","Singular cones after modification":"<p><strong>What it is.</strong> The cones of the modified fan that remain singular.</p><p><strong>How it is calculated.</strong> After ray insertion, every adjacent determinant is recomputed and cones with multiplicity greater than 1 are listed.</p>","Smooth after modification":"<p><strong>What it is.</strong> Whether the modified fan is smooth/Delzant.</p><p><strong>How it is calculated.</strong> The app checks whether every adjacent cone determinant has absolute value 1.</p>","Picard rank after modification":"<p><strong>What it is.</strong> The free divisor-class rank after new rays have been inserted.</p><p><strong>How it is calculated.</strong> For a complete modified fan with \\(r\\) rays, the free rank is \\(r-2\\), with possible torsion recorded separately.</p>","K_X Cartier index after modification":"<p><strong>What it is.</strong> The Cartier index of the canonical divisor for the modified toric fan.</p><p><strong>How it is calculated.</strong> The local Gorenstein index is computed on every adjacent cone of the modified fan and the global index is their least common multiple.</p>","((-K)^2) after modification":"<p><strong>What it is.</strong> The anticanonical self-intersection for the modified toric fan.</p><p><strong>How it is calculated.</strong> The app recomputes the invariant divisor intersection matrix for the new fan and evaluates \\((-K)^2\\) with \\(-K=\\sum_iD_i\\).</p>","Toric fixed points / Euler number":"<p><strong>What it is.</strong> The number of torus fixed points, equal to the number of maximal cones in the complete toric surface fan.</p><p><strong>How it is calculated.</strong> In a complete two-dimensional fan this count equals the number of rays/cones; for smooth compact toric surfaces it also equals the topological Euler characteristic.</p>","Support constants h":"<p><strong>What it is.</strong> The support numbers defining the current divisor/polytope with respect to the fan rays.</p><p><strong>How it is calculated.</strong> For each ray \\(\nu_i\\), the support constant is \\(h_i=\\max_{p\\in P}\\langle\nu_i,p\rangle\\), updated after the selected fan or polygon modification.</p>","Modified polarizing divisor":"<p><strong>What it is.</strong> The divisor class represented by the modified support constants after blow-up or clipping.</p><p><strong>How it is calculated.</strong> The app interprets support constants as coefficients in the torus-invariant divisor basis and evaluates the class through the modified fan intersection matrix.</p>","Clipped / pullback polygon vertices":"<p><strong>What it is.</strong> The polygon obtained after applying the selected toric clipping or pullback-style operation.</p><p><strong>How it is calculated.</strong> The app updates the relevant supporting half-spaces and takes the convex hull of the resulting lattice polygon vertices.</p>","Clipped normalized area":"<p><strong>What it is.</strong> The normalized lattice area of the clipped or transformed polygon.</p><p><strong>How it is calculated.</strong> The app applies the shoelace determinant formula to the clipped vertex list.</p>","Clipped boundary / interior":"<p><strong>What it is.</strong> The boundary and interior lattice-point counts of the clipped polygon.</p><p><strong>How it is calculated.</strong> Boundary points are counted by edge gcd lengths and interior points are obtained from Pick's theorem.</p>","Arithmetic genus of clipped class":"<p><strong>What it is.</strong> The arithmetic genus attached to the clipped polygon/divisor class.</p><p><strong>How it is calculated.</strong> For a lattice polygon it equals the number of strict interior lattice points; equivalently \\(p_a=1+(L^2+K\\cdot L)/2\\).</p>","Pointed formulas":"<p><strong>What it is.</strong> A formula note for quantities depending on a chosen interior origin, especially LDP/Fano and singularity-content diagnostics.</p><p><strong>How it is calculated.</strong> With \\(Q=P-o\\), the app writes \\(Q=\\{x:\\langle n_i,x\rangle\\le h_i\\}\\), then uses facet distances \\(h_i\\), edge widths, and local cone indices to compute pointed indices, polar vertices, and residual basket data.</p>","Symmetry calculation":"<p><strong>What it is.</strong> A note explaining the affine unimodular symmetry computation.</p><p><strong>How it is calculated.</strong> The app tests maps \\(x\\mapsto Ax+b\\) with \\(A\\in GL_2(\\mathbb Z)\\), \\(|\\det A|=1\\), and accepts exactly those preserving the polygon/lattice-point set.</p>"});

Object.assign(HELP_ALIASES,{"\\h^*\\-vector and symmetry":"h^*-vector and symmetry","\\h^*\\ unimodality / log-concavity":"h^* unimodality / log-concavity","Generating functions for \\#(kP\\\\cap M) and \\#((kP)^\\\\circ\\cap M)":"Generating functions for #(kP∩M) and #((kP)^circ∩M)","\\K_X\\ Cartier index":"K_X Cartier index","\\(-K_X)^2\\":"(-K_X)^2","\\L\\· D_i\\ / edge lengths":"L·D_i / edge lengths","Reachable \\\\mathbb P^2\\":"Reachable \\(\\mathbb P^2\\)","Reachable \\\\mathbb F_0\\":"Reachable \\(\\mathbb F_0\\)","\\K^2\\, \\L^2\\, \\(-K).L\\ proxy":"K^2, L^2, (-K).L proxy","\\(\\\\pi^*L-k\\\\sum E_i)^2\\":"((\\pi^*L-k\\sum E_i)^2)","\\K_{\\\\tilde X}\\·(\\\\pi^*L-k\\\\sum E_i)\\":"K_{\\tilde X}\\cdot(\\pi^*L-k\\sum E_i)","\\K_X\\ Cartier index after modification":"K_X Cartier index after modification"});

Object.assign(HELP_ALIASES,{"Generating functions for \\#(kP\\\\cap M) and \\#((kP)^\\\\circ\\\\cap M)":"Generating functions for #(kP∩M) and #((kP)^circ∩M)","Reachable \\\\\\mathbb P^2\\":"Reachable \\(\\mathbb P^2\\)","Reachable \\\\\\mathbb F_0\\":"Reachable \\(\\mathbb F_0\\)"});

Object.assign(HELP_TEXT,{
  "Normal-fan polygon volume":"<p><strong>What it is.</strong> The normalized volume of the normal-fan polygon \\(\\operatorname{conv}(\\nu_1,\\ldots,\\nu_r)\\) in the dual lattice, where the \\(\\nu_i\\) are primitive outward normal rays of the polygon edges.</p><p><strong>How it is calculated.</strong> The app forms the convex hull of the primitive normal rays used in the fan sketch and then applies the shoelace determinant formula to that dual-lattice polygon.</p>",
  "Normal-fan polygon boundary points":"<p><strong>What it is.</strong> The number of lattice points on the boundary of the normal-fan polygon formed by the primitive outward normal rays.</p><p><strong>How it is calculated.</strong> After taking \\(\\operatorname{conv}(\\nu_i)\\), the app sums the lattice lengths of its edges in the dual lattice.</p>",
  "Normal-fan polygon interior points":"<p><strong>What it is.</strong> The number of strict interior lattice points of the normal-fan polygon.</p><p><strong>How it is calculated.</strong> The app computes volume and boundary count of \\(\\operatorname{conv}(\\nu_i)\\), then applies Pick's theorem in the dual lattice.</p>",
  "Minimum-width direction count":"<p><strong>What it is.</strong> The number of unoriented primitive dual-lattice directions attaining the lattice width of the polygon.</p><p><strong>How it is calculated.</strong> The app enumerates primitive covectors in the bounded width search, keeps those with \\(\\operatorname{width}_m(P)=\\operatorname{lw}(P)\\), and identifies \\(m\\) with \\(-m\\).</p>",
  "Interior lattice configuration":"<p><strong>What it is.</strong> The affine dimension of the configuration of strict interior lattice points: empty, single point, collinear segment, or two-dimensional polygon.</p><p><strong>How it is calculated.</strong> The app enumerates strict interior lattice points, takes their convex hull, and checks whether the hull is empty, zero-dimensional, one-dimensional, or two-dimensional.</p>",
  "Interior points collinear":"<p><strong>What it is.</strong> Whether all strict interior lattice points lie on one affine lattice line. This is finer than merely counting interior points.</p><p><strong>How it is calculated.</strong> For at least three interior points, the app tests vanishing determinants relative to the first two interior points; one or two interior points are treated as collinear.</p>",
  "Has reflexive interior origin":"<p><strong>What it is.</strong> Whether some strict interior lattice point can be chosen as an origin so that every facet of the shifted polygon has lattice distance one. This is the pointed reflexivity condition.</p><p><strong>How it is calculated.</strong> The app tries each strict interior lattice point, shifts the polygon by it, computes primitive outward normals, and checks whether all facet support constants equal \\(1\\).</p>",
  "Minkowski decomposable":"<p><strong>What it is.</strong> Whether the polygon has a nontrivial lattice Minkowski decomposition detected by the built-in segment and edge-split routines.</p><p><strong>How it is calculated.</strong> The app first tests segment summands and then searches verified edge-split decompositions with a safety cap, so this filter is exact for the tested bounded routine rather than a direct count proxy.</p>",
  "Torically minimal smooth fan":"<p><strong>What it is.</strong> Whether the normal fan is smooth and has no contractible torus-invariant \\((-1)\\)-curve. It is a toric minimal-model diagnostic.</p><p><strong>How it is calculated.</strong> The app checks cone determinants for smoothness, computes toric self-intersections of the fan rays, and verifies that no ray can be contracted while preserving a smooth fan.</p>",
  "Normal-fan polygon search":"<p><strong>What it is.</strong> The auxiliary search panel for the polygon \\(\\operatorname{conv}(\\nu_1,\\ldots,\\nu_r)\\), the convex hull of the primitive outward normal rays shown in the fan sketch.</p><p><strong>How it is calculated.</strong> The app computes primitive outward normals from the current polygon, forms their convex hull in the dual lattice, displays this normal-fan polygon, and searches the database for AGL₂(ℤ)-equivalent polygons.</p>",
  "Displayed object":"<p><strong>What it is.</strong> The normal-fan polygon attached to the current polygon.</p><p><strong>How it is calculated.</strong> The app displays \\(\\operatorname{conv}(\\nu_i)\\), where the \\(\\nu_i\\) are the primitive outward normal rays of the current polygon edges.</p>",
  "Normal rays used":"<p><strong>What it is.</strong> The primitive outward normal rays \\(\\nu_i\\) of the polygon edges, listed in cyclic order.</p><p><strong>How it is calculated.</strong> Each edge direction is rotated to an outward normal and divided by the gcd of its coordinates to make it primitive.</p>",
  "Normal-fan display grid":"<p><strong>What it is.</strong> The plotting grid required to show the normal-fan polygon.</p><p><strong>How it is calculated.</strong> It is the width and height of the bounding box of \\(\\operatorname{conv}(\\nu_i)\\), with a large-grid guard when the drawing would be too wide or too dense.</p>",
  "Normal-fan polygon stats":"<p><strong>What it is.</strong> The standard lattice statistics of the normal-fan polygon: normalized volume, boundary lattice points, interior lattice points, and total lattice points.</p><p><strong>How it is calculated.</strong> Once \\(\\operatorname{conv}(\\nu_i)\\) is formed, the same exact lattice formulas used for ordinary polygons are applied in the dual lattice.</p>",
  "Normalized volume product proxy":"<p><strong>What it is.</strong> The product of the original polygon's normalized volume and the normal-fan polygon's normalized volume. It is a shape-comparison diagnostic, not the classical Mahler product.</p><p><strong>How it is calculated.</strong> The app multiplies \\(\\operatorname{Vol}(P)\\) by \\(\\operatorname{Vol}(\\operatorname{conv}(\\nu_i))\\).</p>",
  "Barycenter proxy":"<p><strong>What it is.</strong> A comparison of area centroids for the original polygon and the normal-fan polygon.</p><p><strong>How it is calculated.</strong> The app computes polygon area centroids exactly when the grid is not too large; otherwise it skips the normal-fan centroid under the large-grid guard.</p>",
  "Origin in normal-fan polygon":"<p><strong>What it is.</strong> Whether the dual-lattice origin lies strictly inside the normal-fan polygon.</p><p><strong>How it is calculated.</strong> The app runs the same strict interior test used for lattice points on the polygon \\(\\operatorname{conv}(\\nu_i)\\).</p>"
});


Object.assign(HELP_TEXT,{
  "Divisor laboratory":"<p><strong>What it is.</strong> An interactive calculator for torus-invariant divisors \\(D=\\sum_i a_iD_i\\) on the toric surface defined by the current normal fan.</p><p><strong>How it is calculated.</strong> The input coefficients are parsed as rational numbers. The app then uses the fan intersection matrix to compute pairings, self-intersection, positivity against invariant curves, a Riemann-Roch polynomial, and small section-count/cohomology diagnostics.</p>",
  "Divisor input":"<p><strong>What it is.</strong> A divisor written as a string in the ray-divisor basis, for example \\(2D_1-(7/3)D_3\\).</p><p><strong>How it is parsed.</strong> Terms of the form \\(aD_i\\), \\(D_i\\), and rational coefficients such as \\(7/3\\) are accepted. Indices refer to the displayed normal fan rays \\(\\nu_i\\) and invariant divisors \\(D_i\\).</p>",
  "Parsed divisor":"<p><strong>What it is.</strong> The normalized LaTeX form of the divisor after parsing and collecting equal \\(D_i\\)-terms.</p><p><strong>How it is calculated.</strong> Coefficients are stored as exact rational numbers and then displayed in the invariant-divisor basis.</p>",
  "Coefficient vector":"<p><strong>What it is.</strong> The vector \\((a_1,\\ldots,a_r)\\) for \\(D=\\sum_i a_iD_i\\).</p><p><strong>How it is calculated.</strong> The vector is obtained directly from the parsed divisor string, with missing coefficients set to zero.</p>",
  "Cartier / Q-Cartier signal":"<p><strong>What it is.</strong> A local Cartier test for the torus-invariant divisor on every two-dimensional cone of the fan.</p><p><strong>How it is calculated.</strong> For each adjacent cone the app solves for a local linear form \\(m_\\sigma\\) with \\(\\langle m_\\sigma,\\nu_i\\rangle=a_i\\). Integral local forms give Cartier; the least common denominator gives the displayed Q-Cartier index.</p>",
  "Local Cartier data":"<p><strong>What it is.</strong> The local support vectors \\(m_\\sigma\\) on the fan cones.</p><p><strong>How it is calculated.</strong> Each vector is solved exactly from the two adjacent ray equations and listed as a rational coordinate pair.</p>",
  "Degree against L_P":"<p><strong>What it is.</strong> The intersection number \\(D\\cdot L_P\\), using the polarizing divisor coming from the current polygon.</p><p><strong>How it is calculated.</strong> The app forms the toric intersection matrix and pairs the input divisor vector with the support-constant vector of \\(L_P\\).</p>",
  "D^2":"<p><strong>What it is.</strong> The self-intersection of the input divisor.</p><p><strong>How it is calculated.</strong> If \\(Q=(D_i\\cdot D_j)\\) is the invariant-divisor intersection matrix and \\(a=(a_i)\\), the value is \\(a^TQa\\).</p>",
  "(-K_X)·D":"<p><strong>What it is.</strong> The anticanonical degree of the input divisor.</p><p><strong>How it is calculated.</strong> Since \\(-K_X=\\sum_iD_i\\), the app pairs the all-one divisor vector with the input vector using the same intersection matrix.</p>",
  "D·D_i":"<p><strong>What it is.</strong> The intersections of the input divisor with each invariant curve/divisor \\(D_i\\).</p><p><strong>How it is calculated.</strong> These are the entries of \\(a^TQ\\). Their signs give the toric invariant-curve nef and ample test.</p>",
  "Nef / ample result":"<p><strong>What it is.</strong> The positivity result for the divisor against torus-invariant curves.</p><p><strong>How it is calculated.</strong> The divisor is reported nef if every \\(D\\cdot D_i\\ge0\\), and ample if every \\(D\\cdot D_i>0\\), using the complete toric surface invariant-curve test.</p>",
  "Hilbert / Riemann-Roch polynomial":"<p><strong>What it is.</strong> The simplified quadratic Euler-characteristic polynomial attached to multiples of the input divisor.</p><p><strong>How it is calculated.</strong> The app computes \\(D^2\\) and \\((-K_X\\cdot D)\\), then displays \\(\\chi(\\mathcal O_X(kD))=\\frac{D^2}{2}k^2+\\frac{(-K_X\\cdot D)}{2}k+1\\), with zero and unit coefficients simplified.</p>",
  "h^0 lattice count":"<p><strong>What it is.</strong> The number of lattice monomials satisfying the divisor inequalities for the entered divisor.</p><p><strong>How it is calculated.</strong> The app enumerates lattice points in \\(P_D\\cap\\mathbb Z^2\\), where \\(P_D=\\{u\\mid\\langle\\nu_i,u\\rangle\\le a_i\\}\\), and displays the enumeration box as an interval product \\(([x_{\\min},x_{\\max}]\\cap\\mathbb Z)\\times([y_{\\min},y_{\\max}]\\cap\\mathbb Z)\\). For rational divisors this is the integral round-down interpretation used by the inequalities.</p>",
  "Hilbert samples and section counts":"<p><strong>What it is.</strong> A small table comparing section counts and Euler characteristics for several multiples \\(kD\\).</p><p><strong>How it is calculated.</strong> The app enumerates lattice points in the divisor polytope for \\(k=0,\\ldots,5\\) unless the large-grid guard is triggered, and evaluates the Riemann-Roch polynomial at the same values.</p>"
});


Object.assign(HELP_ALIASES,{"Lattice points N":"Lattice points N, dim, codim","Divisor laboratory on modified fan":"Divisor laboratory"});
Object.assign(HELP_TEXT,{
  "Cone modification states":"<p><strong>What it is.</strong> The per-cone blow-up/subdivision state selected in the interactive fan panel.</p><p><strong>How it is calculated.</strong> Smooth cones toggle to ordinary star subdivision; singular cones toggle to a smooth subdivision chain. Manually clicked primitive rays are recorded as custom fan subdivisions for their containing cone.</p>",
  "Fan used for computation":"<p><strong>What it is.</strong> The toric fan on which the divisor laboratory is currently evaluating the input divisor.</p><p><strong>How it is calculated.</strong> For the original laboratory this is the polygon's normal fan. For the blow-up laboratory this is the modified fan obtained from the selected cone states and custom primitive rays.</p>",
  "Degree against polarizing class":"<p><strong>What it is.</strong> The intersection pairing between the input divisor and the current polarizing support divisor.</p><p><strong>How it is calculated.</strong> The app evaluates the toric intersection matrix of the current fan against the divisor coefficient vector and the displayed support constants.</p>"
});

function stripHelpHtml(x){let t=String(x??'').replace(/<[^>]*>/g,' '); t=t.replace(/\\\(|\\\)/g,'').replace(/\$+/g,''); return t.replace(/\s+/g,' ').trim()}
function helpKey(label){let t=stripHelpHtml(label); t=t.replace(/^LP\d{6}(?:\s*\+\s*\d+\s*equivalent record\(s\))?:\s*/,''); t=t.replace(/\s+\d+$/,''); t=t.replace(/\\cdot/g,'·').replace(/\s+/g,' ').trim(); if(HELP_ALIASES[t])return HELP_ALIASES[t]; if(/small-polytopes|\bLDP\b|\bboth\b|\bdrawn\b/.test(t))return 'Source'; if(/^Vol\b/.test(t))return t.includes('B=')?'Vol = L^2 = degree; B=(-K_X)·L':'Vol = L^2 = degree'; if(/^Boundary \/ interior/.test(t))return 'Boundary / interior lattice points'; if(/^Lattice points/.test(t))return 'Lattice points N, dim, codim'; if(/^N, linear-system/.test(t))return 'N, linear-system dim, codim'; if(/^h\^\*-vector/.test(t))return 'h^*-vector and symmetry'; if(/^h\^\* unimodality/.test(t))return 'h^* unimodality / log-concavity'; if(/^Codegree/.test(t))return 'Codegree / h^*-degree'; if(/^K_X Cartier/.test(t))return 'K_X Cartier index'; if(/^\(-K_X\)\^2|^\(-K_X\^2|^-K_X\^2|^\(-K_X\)/.test(t))return '(-K_X)^2'; if(/^L·D_i/.test(t)||/^L\\cdot D_i/.test(t))return 'L·D_i / edge lengths'; if(/^T-singularity quotient data/.test(t))return 'T-singularity quotient data (n,ρ)'; if(/^Singularity content/.test(t))return 'Singularity content / residual basket'; if(/^Diagnostic residual basket/.test(t))return 'Diagnostic residual basket'; if(/^Residual mld/.test(t))return 'Residual mld / min discrepancy proxy'; if(/^Residual canonical/.test(t))return 'Residual canonical / terminal / log terminal proxy'; if(/^Pointed \/ Gorenstein/.test(t))return 'Pointed / Gorenstein index'; if(/^Picard rank/.test(t)&&t.includes('Cox'))return 'Picard rank / Cox variables'; if(/^Picard rank/.test(t)&&t.includes('invariant'))return 'Picard rank / invariant curves'; if(/^L\^2 \/ \(-K\)\.L/.test(t))return 'L^2 / (-K).L proxy'; if(/^K\^2$/.test(t))return 'K^2'; return t}
function helpText(label){let k=helpKey(label); if(HELP_TEXT[k])return HELP_TEXT[k]; if(/^LP\d{6}/.test(stripHelpHtml(label))||/minimum-square display$/.test(k))return '<p><strong>What it is.</strong> The opened record\'s normalized minimum-square drawing of the lattice polygon.</p><p><strong>How it is calculated.</strong> The app chooses an affine unimodular coordinate system minimizing the display square, then plots vertices, boundary lattice points, interior lattice points and the selected origin.</p>'; return `<p><strong>What it is.</strong> This item is an interface field generated by the lattice-polygon database.</p><p><strong>How it is obtained.</strong> Stored identifiers and source labels are read from the metadata table. Geometric, Ehrhart, toric, symmetry, and birational diagnostic values are computed from the currently loaded polygon or fan using exact integer/rational formulas.</p>`}
function escAttr(s){return String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]))}
function helpIcon(label){let body=helpText(label); return `<button type="button" class="help-tip" aria-label="Help: ${escAttr(stripHelpHtml(label))}"><span class="help-mark">?</span><span class="help-panel" role="tooltip">${body}</span></button>`}
function helpLabel(label){return `${label}${helpIcon(label)}`}
function labelLeadText(label){let out=''; for(const n of Array.from(label.childNodes)){if(n.nodeType===3)out+=n.textContent; else if(n.nodeType===1&&n.classList&&n.classList.contains('help-tip'))continue; else break} return out.replace(/\s+/g,' ').trim()}
function insertHelpNodeAfterText(el,label){if(!el||el.dataset.helpDecorated)return; let key=helpKey(label); let span=document.createElement('span'); span.className='help-inline-slot'; span.innerHTML=helpIcon(key); let firstElement=Array.from(el.childNodes).find(n=>n.nodeType===1&&!n.classList?.contains('help-tip')); if(firstElement)el.insertBefore(span,firstElement); else el.appendChild(span); el.dataset.helpDecorated='1'}
function decorateHelp(root=document.body){let scope=root&&root.querySelectorAll?root:document.body; scope.querySelectorAll('label').forEach(l=>{if(l.dataset.helpDecorated)return; let t=labelLeadText(l); if(t)insertHelpNodeAfterText(l,t)}); scope.querySelectorAll('th').forEach(th=>{if(th.dataset.helpDecorated)return; let t=(th.textContent||'').trim(); if(t){th.insertAdjacentHTML('beforeend',helpIcon(t)); th.dataset.helpDecorated='1'}}); scope.querySelectorAll('h2,h3,h4,h5').forEach(h=>{if(h.dataset.helpDecorated||h.closest('.help-panel'))return; let t=(h.textContent||'').replace(/\s+/g,' ').trim(); if(t){h.insertAdjacentHTML('beforeend',helpIcon(t)); h.dataset.helpDecorated='1'}}); scope.querySelectorAll('details.formula > summary, details.advanced > summary, details.adv-group > summary').forEach(sm=>{if(sm.dataset.helpDecorated||sm.querySelector(':scope > .help-tip,:scope > .help-inline-slot'))return; let t=(sm.textContent||'').replace(/\s+/g,' ').trim(); if(t){sm.insertAdjacentHTML('beforeend',helpIcon(t)); sm.dataset.helpDecorated='1'}})}
function renderTooltipMath(el){if(!el||el.dataset.mathRendered||!window.renderMathInElement)return; try{renderMathInElement(el,{delimiters:[{left:'$$',right:'$$',display:true},{left:'\\[',right:'\\]',display:true},{left:'\\(',right:'\\)',display:false}],throwOnError:false}); el.dataset.mathRendered='1'}catch(err){console.warn('Tooltip math render failed',err)}}
function floatingHelpPanel(){let p=document.getElementById('floating-help-panel'); if(!p){p=document.createElement('div'); p.id='floating-help-panel'; p.className='floating-help-panel'; p.setAttribute('role','tooltip'); document.body.appendChild(p)} return p}
function positionFloatingHelpPanel(tip){let panel=floatingHelpPanel(), r=tip.getBoundingClientRect(), gap=9; panel.style.left='0px'; panel.style.top='0px'; panel.classList.add('measure'); let w=panel.offsetWidth, h=panel.offsetHeight, x=r.left+r.width/2-w/2, y=r.bottom+gap; x=Math.max(10,Math.min(x,window.innerWidth-w-10)); if(y+h>window.innerHeight-10)y=Math.max(10,r.top-h-gap); panel.style.left=x+'px'; panel.style.top=y+'px'; panel.classList.toggle('above',y<r.top); panel.classList.remove('measure')}
function showFloatingHelp(tip,pinned=false){let src=tip&&tip.querySelector(':scope > .help-panel'); if(!src)return; let panel=floatingHelpPanel(); if(panel.dataset.sourceTip!==tip.dataset.helpUid){panel.innerHTML=src.innerHTML; delete panel.dataset.mathRendered; panel.dataset.sourceTip=tip.dataset.helpUid||''} panel.classList.add('visible'); panel.classList.toggle('pinned',pinned); renderTooltipMath(panel); positionFloatingHelpPanel(tip)}
function hideFloatingHelp(force=false){let panel=document.getElementById('floating-help-panel'); if(!panel)return; if(!force&&panel.classList.contains('pinned'))return; panel.classList.remove('visible','pinned','above'); panel.dataset.sourceTip=''}
function initHelpInteractions(){let uid=0, pinnedTip=null; document.addEventListener('mouseover',e=>{let tip=e.target.closest('.help-tip'); if(!tip)return; if(pinnedTip&&pinnedTip!==tip)return; if(!tip.dataset.helpUid)tip.dataset.helpUid='h'+(++uid); showFloatingHelp(tip,pinnedTip===tip)}); document.addEventListener('focusin',e=>{let tip=e.target.closest('.help-tip'); if(!tip)return; if(pinnedTip&&pinnedTip!==tip)return; if(!tip.dataset.helpUid)tip.dataset.helpUid='h'+(++uid); showFloatingHelp(tip,pinnedTip===tip)}); document.addEventListener('mouseout',e=>{let tip=e.target.closest('.help-tip'); if(tip&&!pinnedTip&&!tip.contains(e.relatedTarget))hideFloatingHelp(true)}); document.addEventListener('focusout',e=>{let tip=e.target.closest('.help-tip'); if(tip&&!pinnedTip)hideFloatingHelp(true)}); document.addEventListener('click',e=>{let tip=e.target.closest('.help-tip'); if(!tip){pinnedTip=null; document.querySelectorAll('.help-tip.help-open').forEach(x=>x.classList.remove('help-open')); hideFloatingHelp(true); return} e.preventDefault(); e.stopPropagation(); if(!tip.dataset.helpUid)tip.dataset.helpUid='h'+(++uid); document.querySelectorAll('.help-tip.help-open').forEach(x=>{if(x!==tip)x.classList.remove('help-open')}); if(pinnedTip===tip){tip.classList.remove('help-open'); pinnedTip=null; hideFloatingHelp(true)}else{pinnedTip=tip; tip.classList.add('help-open'); showFloatingHelp(tip,true)}}); window.addEventListener('scroll',()=>{if(pinnedTip)positionFloatingHelpPanel(pinnedTip); else hideFloatingHelp(true)},true); window.addEventListener('resize',()=>{if(pinnedTip)positionFloatingHelpPanel(pinnedTip); else hideFloatingHelp(true)}); document.addEventListener('keydown',e=>{if(e.key==='Escape'){pinnedTip=null; document.querySelectorAll('.help-tip.help-open').forEach(x=>x.classList.remove('help-open')); hideFloatingHelp(true)}})}
